 1→// Rundeus Relay — Cloudflare Worker entry point.
 2→// Routes WebSocket upgrades to the RelayDO (one Durable Object per Deus server).
 3→
 4→import { Hono } from "hono";
 5→import { cors } from "hono/cors";
 6→import { createMiddleware } from "hono/factory";
 7→import type { Bindings } from "./types";
 8→
 9→export { RelayDO } from "./relay-do";
10→
11→const app = new Hono<{ Bindings: Bindings }>();
12→
13→// CORS for web portal and local dev
14→app.use(
15→	"*",
16→	cors({
17→		origin: ["https://app.rundeus.com", "http://localhost:3000", "http://localhost:5173"],
18→		allowMethods: ["GET", "POST", "OPTIONS"],
19→		allowHeaders: ["Content-Type", "Authorization"],
20→	}),
21→);
22→
23→// Middleware: validate serverId and attach DO stub to context
24→const withRelay = createMiddleware<{
25→	Bindings: Bindings;
26→	Variables: { stub: DurableObjectStub };
27→}>(async (c, next) => {
28→	const serverId = c.req.param("serverId");
29→	if (!serverId || !/^[a-z0-9]{4,8}$/i.test(serverId)) {
30→		return c.json({ error: "Invalid server ID" }, { status: 400 });
31→	}
32→	const id = c.env.RELAY.idFromName(serverId);
33→	c.set("stub", c.env.RELAY.get(id));
34→	await next();
35→});
36→
37→// Health check
38→app.get("/health", (c) =>
39→	c.json({
40→		status: "ok",
41→		timestamp: new Date().toISOString(),
42→		service: "rundeus-relay",
43→	}),
44→);
45→
46→// Server tunnel — Deus server connects here to register with the relay
47→app.get("/api/servers/:serverId/tunnel", withRelay, async (c) => {
48→	const stub = c.get("stub");
49→	const tunnelUrl = new URL(c.req.url);
50→	tunnelUrl.pathname = "/tunnel";
51→	return stub.fetch(new Request(tunnelUrl, c.req.raw));
52→});
53→
54→// Client connect — remote web/mobile clients connect here
55→app.get("/api/servers/:serverId/connect", withRelay, async (c) => {
56→	const stub = c.get("stub");
57→	const connectUrl = new URL(c.req.url);
58→	connectUrl.pathname = "/connect";
59→	return stub.fetch(new Request(connectUrl, c.req.raw));
60→});
61→
62→// Pairing exchange — web portal exchanges a code for a device token
63→app.get("/api/servers/:serverId/pair", withRelay, async (c) => {
64→	const stub = c.get("stub");
65→	const pairUrl = new URL(c.req.url);
66→	pairUrl.pathname = "/pair";
67→	return stub.fetch(new Request(pairUrl, c.req.raw));
68→});
69→
70→// Server status — check if a server is online
71→app.get("/api/servers/:serverId/status", withRelay, async (c) => {
72→	const stub = c.get("stub");
73→	return stub.fetch(new Request(new URL("/status", c.req.url)));
74→});
75→
76→// Root
77→app.get("/", (c) =>
78→	c.json({
79→		name: "rundeus-relay",
80→		version: "0.1.0",
81→		docs: "https://app.rundeus.com",
82→	}),
83→);
84→
85→export default app;
86→

  1→import * as Sentry from "@sentry/node";
  2→import { serve } from "@hono/node-server";
  3→import { createApp } from "./app";
  4→import { initDatabase, closeDatabase, DB_PATH } from "./lib/database";
  5→import { closeAll as closeAllWsConnections } from "./services/ws.service";
  6→import { ensureRelayConnected, disconnectFromRelay } from "./services/relay.service";
  7→import { getSetting } from "./services/settings.service";
  8→import * as agentService from "./services/agent";
  9→import { stopBrowserServer } from "./services/browser-server.service";
 10→import { destroyAllPtySessions } from "./services/pty.service";
 11→import { destroyAllWatchers } from "./services/fs-watcher.service";
 12→
 13→// Initialize Sentry before anything else.
 14→// DSN passed as env var from Electron main process (not hardcoded — open source repo).
 15→if (process.env.SENTRY_DSN) {
 16→  Sentry.init({
 17→    dsn: process.env.SENTRY_DSN,
 18→    environment: process.env.NODE_ENV === "production" ? "production" : "development",
 19→    sendDefaultPii: false,
 20→    initialScope: { tags: { process: "backend" } },
 21→  });
