 24→/**
 25→ * OpenDevs Backend Server
 26→ *
 27→ * Handles workspace CRUD, sessions, repos, config, and stats.
 28→ * Agent runtime (Claude SDK) is managed by the agent-server (sidecar).
 29→ */
 30→
 31→// Initialize database
 32→const db = initDatabase();
 33→
 34→// Create Hono app + WebSocket injector
 35→const { app, injectWebSocket } = createApp();
 36→
 37→// Global variable to store actual port (used by health endpoint)
 38→let actualServerPort: number | null = null;
 39→
 40→export function getServerPort() {
 41→  return actualServerPort;
 42→}
 43→
 44→// Start server with dynamic port allocation
 45→const PORT = process.env.PORT ? parseInt(process.env.PORT) : 0;
 46→
 47→// Bind 0.0.0.0 to accept connections from all interfaces.
 48→// Remote access is gated by remoteGateMiddleware (rejects non-localhost when disabled).
 49→const server = serve(
 50→  {
 51→    fetch: app.fetch,
 52→    port: PORT,
 53→    hostname: "0.0.0.0",
 54→  },
 55→  (info) => {
 56→    actualServerPort = info.port;
 57→
 58→    // CRITICAL: Machine-readable port output for Electron main process and dev.sh
 59→    console.log(`[BACKEND_PORT]${info.port}`);
 60→
 61→    console.log("\nOpenDevs Backend Server");
 62→    console.log(`API Server: http://0.0.0.0:${info.port}`);
 63→    console.log(`Database: ${DB_PATH}`);
 64→    console.log("Server ready!\n");
 65→  }
 66→);
 67→
 68→// Inject WebSocket support into the HTTP server
 69→injectWebSocket(server);
 70→
 71→const remoteEnabled = getSetting("remote_access_enabled");
 72→if (remoteEnabled === true) {
 73→  ensureRelayConnected();
 74→}
 75→
 76→// Connect to agent-server (sidecar).
 77→//
 78→// Two bootstrap paths:
 79→// 1. AGENT_SERVER_URL is set (dev.sh): sidecar already running, connect directly.
 80→// 2. SIDECAR_BUNDLE_PATH is set (Electron): spawn sidecar as child process,
 81→//    parse LISTEN_URL from its stdout, then connect.
 82→const agentServerUrl = process.env.AGENT_SERVER_URL;
 83→const sidecarBundlePath = process.env.SIDECAR_BUNDLE_PATH;
 84→
 85→if (agentServerUrl) {
 86→  // Path 1: Direct connection (dev.sh spawned the sidecar externally)
 87→  agentService.init(agentServerUrl);
 88→} else if (sidecarBundlePath) {
 89→  // Path 2: Spawn sidecar and connect (Electron desktop mode)
 90→  void spawnSidecarAndConnect(sidecarBundlePath);
 91→}
 92→
 93→// Track sidecar child process for cleanup on shutdown
 94→let sidecarChild: import("child_process").ChildProcess | null = null;
 95→
 96→function killSidecar(): void {
 97→  if (sidecarChild && !sidecarChild.killed) {
 98→    sidecarChild.kill("SIGTERM");
 99→    sidecarChild = null;
100→  }
101→}
102→
103→/** Spawn the sidecar bundle as a child process and connect to its WebSocket. */
104→async function spawnSidecarAndConnect(bundlePath: string): Promise<void> {
105→  const { spawn } = await import("child_process");
106→  const fs = await import("fs");
107→
108→  if (!fs.existsSync(bundlePath)) {
109→    console.error(`[server] Sidecar bundle not found: ${bundlePath}`);
110→    return;
111→  }
112→
113→  sidecarChild = spawn(process.execPath, [bundlePath], {
114→    stdio: ["ignore", "pipe", "pipe"],
115→    env: {
116→      ...process.env,
117→      // Forward database path so sidecar can pass it to agents
118→      DATABASE_PATH: process.env.DATABASE_PATH,
119→      // Forward notebook server path
120→      NOTEBOOK_SERVER_BUNDLE_PATH: process.env.NOTEBOOK_SERVER_BUNDLE_PATH,
121→    },
122→  });
123→
124→  const sidecar = sidecarChild!;
125→  let stdoutBuffer = "";
126→
127→  sidecar.stdout?.on("data", (data: Buffer) => {
128→    stdoutBuffer += data.toString();
129→    const lines = stdoutBuffer.split("\n");
130→    stdoutBuffer = lines.pop() ?? "";
131→
132→    for (const line of lines) {
133→      const trimmed = line.trim();
134→      if (!trimmed) continue;
135→      console.log("[sidecar]", trimmed);
136→
137→      // Capture the LISTEN_URL and connect
138→      if (trimmed.startsWith("LISTEN_URL=")) {
139→        const url = trimmed.slice("LISTEN_URL=".length);
140→        console.log(`[server] Sidecar spawned and listening at ${url}`);
141→        agentService.init(url);
142→      }
143→    }
144→  });
145→
146→  sidecar.stderr?.on("data", (data: Buffer) => {
147→    for (const line of data.toString().split("\n")) {
148→      if (line.trim()) console.error("[sidecar:stderr]", line.trim());
149→    }
150→  });
151→
152→  sidecar.on("exit", (code, signal) => {
153→    console.log(`[sidecar] Exited with code=${code} signal=${signal}`);
154→    sidecarChild = null;
155→  });
156→}
157→
158→// Global error handlers
159→process.on("uncaughtException", (error, origin) => {
160→  console.error("[FATAL] Uncaught Exception:", origin, error);
161→  Sentry.captureException(error);
162→  Sentry.close(2000).finally(() => {
163→    stopBrowserServer();
164→    destroyAllPtySessions();
165→    destroyAllWatchers();
166→    killSidecar();
167→    try {
168→      closeDatabase();
169→    } catch {}
170→    process.exit(1);
171→  });
172→});
173→
174→process.on("unhandledRejection", (reason) => {
175→  // Sentry's built-in onUnhandledRejectionIntegration captures and normalizes
176→  // rejection reasons automatically. We only log here for local visibility.
177→  console.error("[FATAL] Unhandled Promise Rejection:", reason);
178→});
179→
180→// Graceful shutdown
181→function shutdown() {
182→  console.log("\nShutting down...");
183→  agentService.shutdown();
184→  stopBrowserServer();
185→  destroyAllPtySessions();
186→  destroyAllWatchers();
187→  killSidecar();
188→  disconnectFromRelay();
189→  closeAllWsConnections();
190→  closeDatabase();
191→  process.exit(0);
192→}
193→
194→process.on("SIGINT", shutdown);
195→process.on("SIGTERM", shutdown);
196→

