  1→// Cloudflare Durable Object for relay WebSocket multiplexing.
  2→// One DO per Deus server. Holds the server tunnel + all client connections.
  3→// Uses the WebSocket Hibernation API for efficient connection handling.
  4→// All mutable state lives in ctx.storage to survive hibernation.
  5→//
  6→// Storage keys:
  7→//   relayToken                   — server's relay token (set on first registration)
  8→//   tunnelRegistered             — boolean, true after successful register handshake
  9→//   serverDisconnectedAt         — timestamp when server disconnected (persists until reconnect)
 10→//   pending:<clientId>           — auth deadline timestamp for pending clients
 11→//   auth_token:<clientId>        — client's device token (stored for re-forwarding on reconnect)
 12→//   pending:pair:<pairId>       — deadline timestamp for one-shot pairing requests
 13→
 14→import { DurableObject } from "cloudflare:workers";
 15→import type {
 16→	PairerFrame,
 17→	RelayClientFrame,
 18→	RelayFrame,
 19→	RelayPairerFrame,
 20→	ServerFrame,
 21→} from "@cancun/types";
 22→import { clientAuthFrameSchema, pairerFrameSchema, serverFrameSchema } from "@cancun/types";
 23→
 24→const AUTH_TIMEOUT_MS = 5_000;
 25→const OFFLINE_WAIT_MS = 300_000; // 5 min — max time a client waits for server to reconnect
 26→const HEARTBEAT_INTERVAL_MS = 30_000;
 27→const PAIR_TIMEOUT_MS = 30_000;
 28→
 29→export class RelayDO extends DurableObject {
 30→	async fetch(request: Request): Promise<Response> {
 31→		const url = new URL(request.url);
 32→
 33→		if (url.pathname === "/tunnel") {
 34→			return this.handleTunnel(request);
 35→		}
 36→		if (url.pathname === "/connect") {
 37→			return this.handleClient(request);
 38→		}
 39→		if (url.pathname === "/pair") {
 40→			return this.handlePairer(request);
 41→		}
 42→		if (url.pathname === "/status") {
 43→			return this.handleStatus();
 44→		}
 45→
 46→		return new Response("Not found", { status: 404 });
 47→	}
 48→
 49→	// ---- Server Tunnel ----
 50→
 51→	private async handleTunnel(request: Request): Promise<Response> {
 52→		// Authenticate BEFORE closing existing tunnels to prevent unauthenticated
 53→		// connections from disrupting a legitimate server's tunnel (DoS).
 54→		const storedToken = await this.ctx.storage.get<string>("relayToken");
 55→		if (storedToken) {
 56→			const url = new URL(request.url);
 57→			const token =
 58→				request.headers.get("Authorization")?.replace("Bearer ", "") ||
 59→				url.searchParams.get("token");
 60→			if (token !== storedToken) {
 61→				return new Response("Unauthorized", { status: 401 });
 62→			}
 63→		}
 64→
 65→		// Close any existing tunnel before accepting a new one to prevent
 66→		// stale connections from receiving messages meant for the new tunnel.
 67→		const existingTunnels = this.ctx.getWebSockets("tunnel");
 68→		for (const tunnel of existingTunnels) {
 69→			try {
 70→				tunnel.close(1000, "New tunnel connection");
 71→			} catch (err) {
 72→				console.error("relay: failed to close existing tunnel", err);
 73→			}
 74→		}
 75→
 76→		// New tunnel is not yet registered — must complete register handshake first
 77→		await this.ctx.storage.put("tunnelRegistered", false);
 78→
 79→		const pair = new WebSocketPair();
 80→		const [client, server] = Object.values(pair) as [WebSocket, WebSocket];
 81→
 82→		this.ctx.acceptWebSocket(server, ["tunnel"]);
 83→
 84→		return new Response(null, { status: 101, webSocket: client });
 85→	}
 86→
 87→	// ---- Client Connection ----
 88→
 89→	private async handleClient(_request: Request): Promise<Response> {
 90→		const tunnels = this.ctx.getWebSockets("tunnel");
 91→		if (tunnels.length === 0) {
 92→			// Accept connections if server was ever registered — it may come back.
 93→			// Only reject for completely unknown servers (never registered).
 94→			const hasEverRegistered = await this.ctx.storage.get<string>("relayToken");
 95→			if (!hasEverRegistered) {
 96→				return Response.json({ error: "server_not_found" }, { status: 503 });
 97→			}
 98→		}
 99→
100→		const pair = new WebSocketPair();
101→		const [client, server] = Object.values(pair) as [WebSocket, WebSocket];
102→
103→		const clientId = crypto.randomUUID();
104→		// Tags are immutable after acceptWebSocket — don't encode mutable state in them.
105→		// Auth state is tracked via storage keys instead.
106→		this.ctx.acceptWebSocket(server, ["client", clientId]);
107→
108→		// Store auth deadline in durable storage (survives hibernation)
109→		await this.ctx.storage.put(`pending:${clientId}`, Date.now() + AUTH_TIMEOUT_MS);
110→		await this.scheduleNextAlarm();
111→
112→		return new Response(null, { status: 101, webSocket: client });
113→	}
114→
115→	// ---- Status ----
116→
117→	private async handleStatus(): Promise<Response> {
118→		const tunnels = this.ctx.getWebSockets("tunnel");
119→		const allClients = this.ctx.getWebSockets("client");
120→		const pendingClientCount = (await this.getPendingClients()).size;
121→		const serverDisconnectedAt = await this.ctx.storage.get<number>("serverDisconnectedAt");
122→		const serverName = await this.ctx.storage.get<string>("serverName");
123→
124→		return Response.json({
125→			online: tunnels.length > 0,
126→			clients: Math.max(0, allClients.length - pendingClientCount),
127→			reconnecting: serverDisconnectedAt !== undefined,
128→			serverDisconnectedAt: serverDisconnectedAt ?? null,
129→			serverName: serverName || null,
130→		});
131→	}
132→
133→	// ---- Pairing (one-shot code exchange) ----
134→
135→	private async handlePairer(_request: Request): Promise<Response> {
136→		// Pairing requires an active, registered server tunnel
137→		const tunnel = this.getTunnel();
138→		const isRegistered = await this.ctx.storage.get<boolean>("tunnelRegistered");
139→		if (!tunnel || !isRegistered) {
140→			return Response.json({ error: "server_offline" }, { status: 503 });
141→		}
142→
143→		const pair = new WebSocketPair();
144→		const [client, server] = Object.values(pair) as [WebSocket, WebSocket];
145→
146→		const pairId = crypto.randomUUID();
147→		this.ctx.acceptWebSocket(server, ["pairer", pairId]);
148→
149→		// Store deadline for cleanup via alarm
150→		await this.ctx.storage.put(`pending:pair:${pairId}`, Date.now() + PAIR_TIMEOUT_MS);
151→		await this.scheduleNextAlarm();
152→
153→		return new Response(null, { status: 101, webSocket: client });
154→	}
