156→	// ---- WebSocket Handlers (Hibernation API) ----
157→
158→	async webSocketMessage(ws: WebSocket, message: string | ArrayBuffer): Promise<void> {
159→		const tags = this.ctx.getTags(ws);
160→		const raw = typeof message === "string" ? message : new TextDecoder().decode(message);
161→
162→		let json: unknown;
163→		try {
164→			json = JSON.parse(raw);
165→		} catch {
166→			console.error("relay: failed to parse WebSocket message as JSON");
167→			return;
168→		}
169→
170→		if (tags.includes("tunnel")) {
171→			const result = serverFrameSchema.safeParse(json);
172→			if (!result.success) {
173→				console.error("relay: invalid server frame", result.error.issues);
174→				return;
175→			}
176→			await this.handleServerMessage(ws, result.data);
177→		} else if (tags.includes("pairer")) {
178→			const pairId = tags.find((t) => t !== "pairer");
179→			if (!pairId) return;
180→			const result = pairerFrameSchema.safeParse(json);
181→			if (!result.success) {
182→				console.error("relay: invalid pairer frame", result.error.issues);
183→				return;
184→			}
185→			await this.handlePairerMessage(pairId, result.data);
186→		} else if (tags.includes("client")) {
187→			const clientId = tags.find((t) => t !== "client");
188→			if (!clientId) return;
189→			await this.handleClientMessage(clientId, json);
190→		}
191→	}
