193→	async webSocketClose(
194→		ws: WebSocket,
195→		_code: number,
196→		_reason: string,
197→		_wasClean: boolean,
198→	): Promise<void> {
199→		const tags = this.ctx.getTags(ws);
200→
201→		if (tags.includes("tunnel")) {
202→			await this.handleServerDisconnect();
203→		} else if (tags.includes("pairer")) {
204→			const pairId = tags.find((t) => t !== "pairer");
205→			if (pairId) {
206→				await this.ctx.storage.delete(`pending:pair:${pairId}`);
207→			}
208→		} else if (tags.includes("client")) {
209→			const clientId = tags.find((t) => t !== "client");
210→			if (clientId) {
211→				await this.handleClientDisconnect(clientId);
212→			}
213→		}
214→	}
