234→	// ---- Alarm (auth timeout + heartbeat) ----
235→
236→	async alarm(): Promise<void> {
237→		const now = Date.now();
238→
239→		// 1. Reject clients whose auth deadline has expired
240→		const pendingClients = await this.getPendingClients();
241→		const expiredClientIds: string[] = [];
242→		for (const [clientId, deadline] of pendingClients) {
243→			if (now >= deadline) {
244→				expiredClientIds.push(clientId);
245→			}
246→		}
247→		if (expiredClientIds.length > 0) {
248→			const keysToDelete = expiredClientIds.flatMap((id) => [`pending:${id}`, `auth_token:${id}`]);
249→			await this.ctx.storage.delete(keysToDelete);
250→			for (const clientId of expiredClientIds) {
251→				this.rejectClient(clientId, "Authentication timeout");
252→			}
253→		}
254→
255→		// 1b. Reject pairers whose deadline has expired
256→		const pendingPairs = await this.ctx.storage.list<number>({ prefix: "pending:pair:" });
257→		for (const [key, deadline] of pendingPairs) {
258→			if (now >= deadline) {
259→				const pairId = key.slice("pending:pair:".length);
260→				const pairerWs = this.findPairerWs(pairId);
261→				if (pairerWs) {
262→					this.safeSend(pairerWs, { type: "pair_failed", message: "Pairing timed out" });
263→					try {
264→						pairerWs.close(1000, "Pairing timed out");
265→					} catch (err) {
266→						console.error("relay: failed to close expired pairer", err);
267→					}
268→				}
269→				await this.ctx.storage.delete(key);
270→			}
271→		}
272→
273→		// 2. Send heartbeat ping to server
274→		const tunnel = this.getTunnel();
275→		if (tunnel) {
276→			this.safeSend(tunnel, { type: "ping" });
277→		}
278→
279→		// 3. Reschedule for next event
280→		await this.scheduleNextAlarm();
281→	}
