283→	// ---- Server Message Handling ----
284→
285→	private async handleServerMessage(ws: WebSocket, frame: ServerFrame): Promise<void> {
286→		const isRegistered = await this.ctx.storage.get<boolean>("tunnelRegistered");
287→
288→		switch (frame.type) {
289→			case "register": {
290→				await this.handleRegister(ws, frame);
291→				break;
292→			}
293→			case "auth_response": {
294→				// Only registered tunnels may send auth_response
295→				if (!isRegistered) break;
296→				await this.handleAuthResponse(frame.clientId, frame.allowed, frame.reason);
297→				break;
298→			}
299→			case "pair_response": {
300→				if (!isRegistered) break;
301→				await this.ctx.storage.delete(`pending:pair:${frame.pairId}`);
302→				const pairerWs = this.findPairerWs(frame.pairId);
303→				if (!pairerWs) break;
304→				if (frame.success && frame.deviceToken) {
305→					this.safeSend(pairerWs, { type: "pair_success", token: frame.deviceToken });
306→				} else {
307→					this.safeSend(pairerWs, {
308→						type: "pair_failed",
309→						message: frame.reason || "Pairing failed",
310→					});
311→				}
312→				// Close the one-shot pairer WS — buffered messages are sent before the close frame
313→				try {
314→					pairerWs.close(1000, "Pairing complete");
315→				} catch (err) {
316→					console.error("relay: failed to close pairer after response", err);
317→				}
318→				break;
319→			}
320→			case "data": {
321→				// Only registered tunnels may send data
322→				if (!isRegistered) break;
323→				await this.forwardToClient(frame.clientId, frame.payload);
324→				break;
325→			}
326→			case "pong": {
327→				break;
328→			}
329→		}
330→	}
331→
332→	private async handleRegister(
333→		ws: WebSocket,
334→		frame: Extract<ServerFrame, { type: "register" }>,
335→	): Promise<void> {
336→		const storedToken = await this.ctx.storage.get<string>("relayToken");
337→		if (storedToken && storedToken !== frame.relayToken) {
338→			this.safeSend(ws, { type: "error", message: "Invalid relay token" });
339→			try {
340→				ws.close(4003, "Invalid relay token");
341→			} catch (err) {
342→				console.error("relay: failed to close tunnel with bad token", err);
343→			}
344→			return;
345→		}
346→
347→		if (!storedToken) {
348→			await this.ctx.storage.put("relayToken", frame.relayToken);
349→		}
350→
351→		// Always update server name (user might have changed it)
352→		if (frame.serverName) {
353→			await this.ctx.storage.put("serverName", frame.serverName);
354→		}
355→
356→		// Mark tunnel as registered — gates auth_response/data processing
357→		await this.ctx.storage.put("tunnelRegistered", true);
358→
359→		// Clear reconnection state and notify clients server is back
360→		const wasReconnecting = await this.ctx.storage.get<number>("serverDisconnectedAt");
361→		await this.ctx.storage.delete("serverDisconnectedAt");
362→
363→		// Confirm registration to the WebSocket that sent it
364→		this.safeSend(ws, { type: "registered" });
365→
366→		// Notify already-authenticated clients that the server is back.
367→		// Pending clients are notified via the normal auth flow (they'll get "authenticated").
368→		if (wasReconnecting !== undefined) {
369→			const clients = this.ctx.getWebSockets("client");
370→			for (const clientWs of clients) {
371→				const clientId = this.ctx.getTags(clientWs).find((t) => t !== "client");
372→				if (!clientId) continue;
373→				const isPending = await this.ctx.storage.get<number>(`pending:${clientId}`);
374→				if (isPending !== undefined) continue;
375→				this.safeSend(clientWs, { type: "server_connected" });
376→			}
377→		}
378→
379→		// Always re-forward pending clients' stored auth tokens to the new tunnel.
380→		// This handles both reconnection (wasReconnecting) and tunnel replacement
381→		// (where serverDisconnectedAt was never set because the old tunnel's close
382→		// handler saw the new tunnel already existed).
383→		const pendingClients = await this.getPendingClients();
384→		for (const [pendingClientId] of pendingClients) {
385→			const storedAuthToken = await this.ctx.storage.get<string>(`auth_token:${pendingClientId}`);
386→			if (storedAuthToken) {
387→				this.safeSend(ws, {
388→					type: "client_connected",
389→					clientId: pendingClientId,
390→					deviceToken: storedAuthToken,
391→				});
392→			}
393→		}
394→
395→		// Start heartbeat
396→		await this.scheduleNextAlarm();
397→	}
