435→	// ---- Client Message Handling ----
436→
437→	private async handleClientMessage(clientId: string, json: unknown): Promise<void> {
438→		const isPending = await this.ctx.storage.get<number>(`pending:${clientId}`);
439→
440→		if (isPending !== undefined) {
441→			// Client is still pending — only accept authenticate messages
442→			const authResult = clientAuthFrameSchema.safeParse(json);
443→			if (!authResult.success) return;
444→
445→			const { token } = authResult.data;
446→			// Store the token so we can re-forward it if the server reconnects
447→			await this.ctx.storage.put(`auth_token:${clientId}`, token);
448→
449→			const tunnel = this.getTunnel();
450→			const isRegistered = await this.ctx.storage.get<boolean>("tunnelRegistered");
451→			if (tunnel && isRegistered) {
452→				this.safeSend(tunnel, {
453→					type: "client_connected",
454→					clientId,
455→					deviceToken: token,
456→				});
457→			} else if (tunnel) {
458→				// Tunnel exists but not yet registered — replacement in progress.
459→				// Leave client pending; handleRegister will re-forward the stored
460→				// auth token once the new tunnel completes registration.
461→				// The auth timeout alarm will reject naturally if registration never comes.
462→			} else {
463→				// Server tunnel is down — keep client waiting for server to return.
464→				// Suspend the short auth deadline; handleRegister will re-forward the
465→				// stored auth token when the server reconnects.
466→				const serverDisconnectedAt = await this.ctx.storage.get<number>("serverDisconnectedAt");
467→				await this.ctx.storage.put(`pending:${clientId}`, Date.now() + OFFLINE_WAIT_MS);
468→				const clientWs = this.findClientWs(clientId);
469→				if (clientWs) {
470→					const serverName = await this.ctx.storage.get<string>("serverName");
471→					this.safeSend(clientWs, {
472→						type: "server_reconnecting",
473→						serverDisconnectedAt: serverDisconnectedAt ?? Date.now(),
474→						serverName: serverName || null,
475→					});
476→				}
477→			}
478→			return;
479→		}
480→
481→		// Authenticated client — forward data to server
482→		const tunnel = this.getTunnel();
483→		if (tunnel) {
484→			this.safeSend(tunnel, {
485→				type: "data",
486→				clientId,
487→				payload: JSON.stringify(json),
488→			});
489→		}
490→	}
491→
492→	// ---- Pairer Message Handling ----
493→
494→	private async handlePairerMessage(pairId: string, frame: PairerFrame): Promise<void> {
495→		const isPending = await this.ctx.storage.get<number>(`pending:pair:${pairId}`);
496→		if (isPending === undefined) return;
497→
498→		const tunnel = this.getTunnel();
499→		const isRegistered = await this.ctx.storage.get<boolean>("tunnelRegistered");
500→		if (tunnel && isRegistered) {
501→			this.safeSend(tunnel, {
502→				type: "pair_request",
503→				pairId,
504→				code: frame.code,
505→				deviceName: frame.deviceName,
506→			});
507→		} else {
508→			const pairerWs = this.findPairerWs(pairId);
509→			if (pairerWs) {
510→				this.safeSend(pairerWs, { type: "pair_failed", message: "Server is offline" });
511→				try {
512→					pairerWs.close(1000, "Server offline");
513→				} catch (err) {
514→					console.error("relay: failed to close pairer (server offline)", err);
515→				}
516→			}
517→			await this.ctx.storage.delete(`pending:pair:${pairId}`);
518→		}
519→	}
