521→	// ---- Client/Server Lifecycle ----
522→
523→	private async handleClientDisconnect(clientId: string): Promise<void> {
524→		await this.ctx.storage.delete(`pending:${clientId}`);
525→		await this.ctx.storage.delete(`auth_token:${clientId}`);
526→
527→		const tunnel = this.getTunnel();
528→		if (tunnel) {
529→			this.safeSend(tunnel, {
530→				type: "client_disconnected",
531→				clientId,
532→			});
533→		}
534→	}
