562→	// ---- Data Forwarding ----
563→
564→	private async forwardToClient(clientId: string, payload: string): Promise<void> {
565→		const isPending = await this.ctx.storage.get<number>(`pending:${clientId}`);
566→		if (isPending !== undefined) {
567→			return;
568→		}
569→
570→		const ws = this.findClientWs(clientId);
571→		if (ws) {
572→			try {
573→				ws.send(payload);
574→			} catch (err) {
575→				console.error(`relay: failed to forward data to client ${clientId}`, err);
576→			}
577→		}
578→	}
579→
580→	// ---- Alarm Scheduling ----
581→
582→	private async scheduleNextAlarm(): Promise<void> {
583→		const now = Date.now();
584→		const candidates: number[] = [];
585→
586→		// Earliest pending auth deadline
587→		const pendingClients = await this.ctx.storage.list<number>({ prefix: "pending:" });
588→		for (const [, deadline] of pendingClients) {
589→			candidates.push(deadline);
590→		}
591→
592→		// Earliest pending pair deadline
593→		const pendingPairs = await this.ctx.storage.list<number>({ prefix: "pending:pair:" });
594→		for (const [, deadline] of pendingPairs) {
595→			candidates.push(deadline);
596→		}
597→
598→		// Heartbeat interval (only if server is connected)
599→		const tunnels = this.ctx.getWebSockets("tunnel");
600→		if (tunnels.length > 0) {
601→			candidates.push(now + HEARTBEAT_INTERVAL_MS);
602→		}
603→
604→		if (candidates.length > 0) {
605→			const nextAlarm = Math.min(...candidates);
606→			// Ensure alarm is at least 100ms in the future
607→			await this.ctx.storage.setAlarm(Math.max(nextAlarm, now + 100));
608→		}
609→	}
610→
611→	// ---- Helpers ----
612→
613→	/** Get pending client auth entries, filtering out pair entries that share the prefix. */
614→	private async getPendingClients(): Promise<Map<string, number>> {
615→		const entries = await this.ctx.storage.list<number>({ prefix: "pending:" });
616→		const result = new Map<string, number>();
617→		for (const [key, deadline] of entries) {
618→			if (key.startsWith("pending:pair:")) continue;
619→			result.set(key.slice("pending:".length), deadline);
620→		}
621→		return result;
622→	}
623→
624→	private findClientWs(clientId: string): WebSocket | null {
625→		const allClients = this.ctx.getWebSockets("client");
626→		for (const ws of allClients) {
627→			const tags = this.ctx.getTags(ws);
628→			if (tags.includes(clientId)) return ws;
629→		}
630→		return null;
631→	}
632→
633→	private findPairerWs(pairId: string): WebSocket | null {
634→		const allPairers = this.ctx.getWebSockets("pairer");
635→		for (const ws of allPairers) {
636→			const tags = this.ctx.getTags(ws);
637→			if (tags.includes(pairId)) return ws;
638→		}
639→		return null;
640→	}
641→
642→	private getTunnel(): WebSocket | null {
643→		const tunnels = this.ctx.getWebSockets("tunnel");
644→		return tunnels[0] ?? null;
645→	}
646→
647→	private safeSend(ws: WebSocket, data: RelayFrame | RelayClientFrame | RelayPairerFrame): void {
648→		try {
649→			ws.send(JSON.stringify(data));
650→		} catch (err) {
651→			console.error("relay: safeSend failed", err);
652→		}
653→	}
654→}
