 1→// Relay envelope protocol types.
 2→// Defines the framing between Deus server ↔ CF Durable Object relay ↔ web clients.
 3→
 4→import { z } from "zod";
 5→
 6→// ---- Server ↔ Relay (tunnel) ----
 7→
 8→/** Frames sent from Deus server to relay via tunnel WebSocket */
 9→export type ServerFrame =
10→	| { type: "register"; serverId: string; relayToken: string; serverName?: string }
11→	| { type: "data"; clientId: string; payload: string }
12→	| { type: "auth_response"; clientId: string; allowed: boolean; reason?: string }
13→	| {
14→			type: "pair_response";
15→			pairId: string;
16→			success: boolean;
17→			deviceToken?: string;
18→			reason?: string;
19→	  }
20→	| { type: "pong" };
21→
22→/** Frames sent from relay to Deus server via tunnel WebSocket */
23→export type RelayFrame =
24→	| { type: "registered" }
25→	| { type: "client_connected"; clientId: string; deviceToken: string }
26→	| { type: "client_disconnected"; clientId: string }
27→	| { type: "data"; clientId: string; payload: string }
28→	| { type: "pair_request"; pairId: string; code: string; deviceName: string }
29→	| { type: "ping" }
30→	| { type: "error"; message: string };
31→
32→// ---- Client ↔ Relay ----
33→
34→/** First message a client sends after WebSocket connect */
35→export type ClientAuthFrame = { type: "authenticate"; token: string };
36→
37→/** Control frames sent from relay to client (auth + lifecycle) */
38→export type RelayClientFrame =
39→	| { type: "authenticated" }
40→	| { type: "auth_failed"; message: string }
41→	| { type: "server_offline"; serverName: string | null; serverDisconnectedAt: number }
42→	| { type: "server_reconnecting"; serverName: string | null; serverDisconnectedAt: number }
43→	| { type: "server_connected" }
44→	| { type: "error"; message: string };
45→
46→// ---- Pairer ↔ Relay ----
47→
48→/** Frame sent from pairer (web browser) to relay */
49→export type PairerFrame = { type: "pair_request"; code: string; deviceName: string };
50→
51→/** Frames sent from relay to pairer */
52→export type RelayPairerFrame =
53→	| { type: "pair_success"; token: string }
54→	| { type: "pair_failed"; message: string };
55→
56→// ---- Zod Schemas (inbound validation) ----
57→
58→export const serverFrameSchema = z.discriminatedUnion("type", [
59→	z.object({
60→		type: z.literal("register"),
61→		serverId: z.string(),
62→		relayToken: z.string(),
63→		serverName: z.string().optional(),
64→	}),
65→	z.object({
66→		type: z.literal("data"),
67→		clientId: z.string(),
68→		payload: z.string(),
69→	}),
70→	z.object({
71→		type: z.literal("auth_response"),
72→		clientId: z.string(),
73→		allowed: z.boolean(),
74→		reason: z.string().optional(),
75→	}),
76→	z.object({
77→		type: z.literal("pair_response"),
78→		pairId: z.string(),
79→		success: z.boolean(),
80→		deviceToken: z.string().optional(),
81→		reason: z.string().optional(),
82→	}),
83→	z.object({ type: z.literal("pong") }),
84→]);
85→
86→export const clientAuthFrameSchema = z.object({
87→	type: z.literal("authenticate"),
88→	token: z.string(),
89→});
90→
91→export const pairerFrameSchema = z.object({
92→	type: z.literal("pair_request"),
93→	code: z.string(),
94→	deviceName: z.string().default("Web Browser"),
95→});
