  1→// backend/src/services/ws.service.ts
  2→// WebSocket connection manager for remote access.
  3→// Manages connected clients, heartbeat pings, message routing, and protocol dispatch.
  4→
  5→import { match } from "ts-pattern";
  6→import type { WSContext } from "hono/ws";
  7→
  8→/** Minimal interface for sending/closing WebSocket-like connections.
  9→ *  WSContext already satisfies this — used to also accept virtual relay connections. */
 10→export interface WsSendable {
 11→  send(data: string | ArrayBuffer): void;
 12→  close(code?: number, reason?: string): void;
 13→}
 14→
 15→export interface WsConnection {
 16→  id: string;
 17→  ws: WsSendable;
 18→  deviceId: string | null;
 19→  lastPong: number;
 20→  /** True for relay-tunneled connections (skip direct heartbeat pings) */
 21→  isVirtual?: boolean;
 22→}
 23→
 24→// ---- State ----
 25→
 26→const connections = new Map<string, WsConnection>();
 27→let heartbeatInterval: ReturnType<typeof setInterval> | null = null;
 28→
 29→const HEARTBEAT_INTERVAL_MS = 30_000;
 30→const HEARTBEAT_TIMEOUT_MS = 10_000;
 31→
 32→// ---- Public API ----
 33→
 34→/** Register a new WebSocket connection. Returns the connection ID. */
 35→export function addConnection(ws: WsSendable, deviceId: string | null, isVirtual = false): string {
 36→  const id = crypto.randomUUID();
 37→  connections.set(id, {
 38→    id,
 39→    ws,
 40→    deviceId,
 41→    lastPong: Date.now(),
 42→    isVirtual,
 43→  });
 44→
 45→  startHeartbeat();
 46→  return id;
 47→}
 48→
 49→/** Remove a connection by ID. */
 50→export function removeConnection(id: string): void {
 51→  connections.delete(id);
 52→  if (connections.size === 0) stopHeartbeat();
 53→}
 54→
 55→/** Get a connection by ID. */
 56→export function getConnection(id: string): WsConnection | undefined {
 57→  return connections.get(id);
 58→}
 59→
 60→/** Record a pong from a client. */
 61→export function recordPong(id: string): void {
 62→  const conn = connections.get(id);
 63→  if (conn) conn.lastPong = Date.now();
 64→}
 65→
 66→/** Broadcast a message to all connected clients. */
 67→export function broadcast(message: string): void {
 68→  for (const conn of connections.values()) {
 69→    try {
 70→      conn.ws.send(message);
 71→    } catch {
 72→      // Connection may have closed — will be cleaned up on next heartbeat
 73→    }
 74→  }
 75→}
 76→
 77→/** Get number of active connections. */
 78→export function getConnectionCount(): number {
 79→  return connections.size;
 80→}
 81→
 82→/** Close all connections and stop heartbeat (for shutdown). */
 83→export function closeAll(): void {
 84→  stopHeartbeat();
 85→  for (const conn of connections.values()) {
 86→    try {
 87→      conn.ws.close(1001, "Server shutting down");
 88→    } catch {
 89→      // Best-effort
 90→    }
 91→  }
 92→  connections.clear();
 93→}
 94→
 95→// ---- Heartbeat ----
 96→
 97→function startHeartbeat(): void {
 98→  if (heartbeatInterval) return;
 99→  heartbeatInterval = setInterval(checkHeartbeats, HEARTBEAT_INTERVAL_MS);
100→}
101→
102→function stopHeartbeat(): void {
103→  if (heartbeatInterval) {
104→    clearInterval(heartbeatInterval);
105→    heartbeatInterval = null;
106→  }
107→}
108→
109→function checkHeartbeats(): void {
110→  const now = Date.now();
111→  for (const [id, conn] of connections) {
112→    // Virtual connections are managed by the relay tunnel — skip direct heartbeat
113→    if (conn.isVirtual) continue;
114→
115→    if (now - conn.lastPong > HEARTBEAT_INTERVAL_MS + HEARTBEAT_TIMEOUT_MS) {
116→      // Client hasn't responded to pings — close
117→      console.log(`[WS] Closing stale connection: ${id}`);
118→      try {
119→        conn.ws.close(1001, "Heartbeat timeout");
120→      } catch {
121→        // Already closed
122→      }
123→      connections.delete(id);
124→      continue;
125→    }
126→
127→    // Send ping
128→    try {
129→      conn.ws.send(JSON.stringify({ type: "ping" }));
130→    } catch {
131→      connections.delete(id);
132→    }
133→  }
134→
135→  if (connections.size === 0) stopHeartbeat();
136→}
137→
138→// ---- Protocol Dispatch ----
139→
140→/** Handler for q:* query protocol frames. */
141→export interface WsProtocolHandlers {
142→  onQueryFrame?: (connectionId: string, msg: Record<string, unknown>) => void;
143→}
144→
145→let extendedHandlers: WsProtocolHandlers = {};
146→
147→/** Register handlers for extended protocol messages. Called once at startup. */
148→export function setProtocolHandlers(handlers: WsProtocolHandlers): void {
149→  extendedHandlers = handlers;
150→}
151→
152→/**
153→ * Handle an incoming WS protocol message for an authenticated connection.
154→ * Shared by local WS (app.ts) and virtual relay connections (relay.service.ts).
155→ *
156→ * Core: pong
157→ * Query protocol: q:* frames routed to query engine
158→ */
159→export function handleProtocolMessage(connectionId: string, msg: Record<string, unknown>): void {
160→  match(msg.type as string)
161→    .with("pong", () => {
162→      recordPong(connectionId);
163→    })
164→    .otherwise(() => {
165→      // Route q:* frames to query engine handler
166→      if (typeof msg.type === "string" && msg.type.startsWith("q:")) {
167→        extendedHandlers.onQueryFrame?.(connectionId, msg);
168→      }
169→    });
170→}
171→

 1→export const DEFAULT_RELAY_URL = "wss://relay.rundeus.com";
 2→
 3→export function isLocalhost(ip: string | undefined): boolean {
 4→  if (!ip) return false;
 5→  return ip === "127.0.0.1" || ip === "::1" || ip === "::ffff:127.0.0.1" || ip === "localhost";
 6→}
 7→
 8→export function getClientIp(c: any): string | undefined {
 9→  return (
10→    (c.env as any)?.incoming?.socket?.remoteAddress ||
11→    c.req.header("x-forwarded-for")?.split(",")[0]?.trim() ||
12→    c.req.header("x-real-ip")
13→  );
14→}
