  1→// WebSocket client for connecting to the relay.
  2→// Handles authentication, reconnection, and message dispatch.
  3→
  4→import type { RelayClientFrame, RelayPairerFrame } from "@cancun/types";
  5→
  6→export type RelayStatus = "connecting" | "authenticating" | "connected" | "disconnected" | "error";
  7→
  8→export interface ServerOfflineInfo {
  9→	serverName: string | null;
 10→	disconnectedAt: number | null;
 11→}
 12→
 13→export interface RelayClientOptions {
 14→	relayUrl: string;
 15→	serverId: string;
 16→	token: string;
 17→	onStatusChange: (status: RelayStatus) => void;
 18→	onMessage: (data: unknown) => void;
 19→	onError?: (error: string) => void;
 20→	onServerOffline?: (info: ServerOfflineInfo | null) => void;
 21→}
 22→
 23→export class RelayClient {
 24→	private ws: WebSocket | null = null;
 25→	private options: RelayClientOptions;
 26→	private reconnectTimer: ReturnType<typeof setTimeout> | null = null;
 27→	private reconnectAttempt = 0;
 28→	private disposed = false;
 29→
 30→	constructor(options: RelayClientOptions) {
 31→		this.options = options;
 32→	}
 33→
 34→	connect(): void {
 35→		if (this.disposed) return;
 36→		// Cancel any pending reconnect timer so we don't double-open after a
 37→		// manual retry.
 38→		if (this.reconnectTimer) {
 39→			clearTimeout(this.reconnectTimer);
 40→			this.reconnectTimer = null;
 41→		}
 42→		// Close any in-flight connection before opening a new one to prevent
 43→		// orphaned WebSockets whose onclose triggers ghost reconnects.
 44→		if (this.ws && this.ws.readyState !== WebSocket.CLOSED) {
 45→			this.ws.onclose = null;
 46→			this.ws.close();
 47→			this.ws = null;
 48→		}
 49→		this.options.onStatusChange("connecting");
 50→
 51→		const url = `${this.options.relayUrl}/api/servers/${this.options.serverId}/connect`;
 52→		try {
 53→			this.ws = new WebSocket(url);
 54→		} catch {
 55→			this.options.onStatusChange("error");
 56→			this.scheduleReconnect();
 57→			return;
 58→		}
 59→
 60→		this.ws.onopen = () => {
 61→			this.options.onStatusChange("authenticating");
 62→			this.ws?.send(JSON.stringify({ type: "authenticate", token: this.options.token }));
 63→		};
 64→
 65→		this.ws.onmessage = (event) => {
 66→			try {
 67→				const data = JSON.parse(event.data);
 68→
 69→				switch (data.type) {
 70→					case "authenticated":
 71→						this.reconnectAttempt = 0;
 72→						this.options.onStatusChange("connected");
 73→						return;
 74→					case "auth_failed": {
 75→						const frame = data as Extract<RelayClientFrame, { type: "auth_failed" }>;
 76→						this.options.onError?.(frame.message || "Authentication failed");
 77→						this.options.onStatusChange("error");
 78→						// Use disconnect() to set disposed=true and prevent infinite reconnect
 79→						// with the same bad token.
 80→						this.disconnect();
 81→						return;
 82→					}
 83→					case "server_offline": {
 84→						const frame = data as Extract<RelayClientFrame, { type: "server_offline" }>;
 85→						this.options.onServerOffline?.({
 86→							serverName: frame.serverName,
 87→							disconnectedAt: frame.serverDisconnectedAt,
 88→						});
 89→						this.options.onError?.("Server is offline");
 90→						this.options.onStatusChange("disconnected");
 91→						return;
 92→					}
 93→					case "server_reconnecting": {
 94→						const frame = data as Extract<RelayClientFrame, { type: "server_reconnecting" }>;
 95→						this.options.onServerOffline?.({
 96→							serverName: frame.serverName,
 97→							disconnectedAt: frame.serverDisconnectedAt,
 98→						});
 99→						this.options.onStatusChange("connecting");
100→						return;
101→					}
102→					case "server_connected":
103→						this.options.onServerOffline?.(null);
104→						this.options.onStatusChange("connected");
105→						return;
106→				}
107→
108→				// Regular data message from server (transparent pipe)
109→				this.options.onMessage(data);
110→			} catch {
111→				// Ignore malformed
112→			}
113→		};
114→
115→		this.ws.onclose = () => {
116→			if (!this.disposed) {
117→				this.options.onStatusChange("disconnected");
118→				this.scheduleReconnect();
119→			}
120→		};
121→
122→		this.ws.onerror = () => {
123→			// Details come through onclose
124→		};
125→	}
126→
127→	send(data: unknown): void {
128→		if (this.ws?.readyState === WebSocket.OPEN) {
129→			this.ws.send(JSON.stringify(data));
130→		}
131→	}
132→
133→	/** One-shot pairing exchange: opens /pair WS, sends code, returns device token. */
134→	static pair(
135→		relayUrl: string,
136→		serverId: string,
137→		code: string,
138→		deviceName: string,
139→	): Promise<string> {
140→		return new Promise((resolve, reject) => {
141→			const url = `${relayUrl}/api/servers/${serverId}/pair`;
142→			let ws: WebSocket;
143→			try {
144→				ws = new WebSocket(url);
145→			} catch {
146→				return reject(new Error("Failed to open pairing connection"));
147→			}
148→
149→			const timeout = setTimeout(() => {
150→				ws.close();
151→				reject(new Error("Pairing timed out"));
152→			}, 30_000);
153→
154→			const cleanup = () => clearTimeout(timeout);
155→			let settled = false;
156→			const finish = (fn: () => void) => {
157→				if (settled) return;
158→				settled = true;
159→				cleanup();
160→				fn();
161→			};
162→
163→			ws.onopen = () => {
164→				ws.send(JSON.stringify({ type: "pair_request", code, deviceName }));
165→			};
166→
167→			ws.onmessage = (event) => {
168→				try {
169→					const data = JSON.parse(event.data) as RelayPairerFrame;
170→					if (data.type === "pair_success") {
171→						finish(() => {
172→							ws.close(1000);
173→							resolve(data.token);
174→						});
175→					} else if (data.type === "pair_failed") {
176→						finish(() => {
177→							ws.close(1000);
178→							reject(new Error(data.message || "Pairing failed"));
179→						});
180→					}
181→					// Ignore unrelated messages — keep timeout running
182→				} catch {
183→					finish(() => {
184→						ws.close();
185→						reject(new Error("Invalid response from relay"));
186→					});
187→				}
188→			};
189→
190→			ws.onerror = () => {
191→				finish(() => reject(new Error("Connection to relay failed")));
192→			};
193→
194→			ws.onclose = (ev) => {
195→				if (ev.code !== 1000) {
196→					finish(() => reject(new Error("Connection closed unexpectedly")));
197→				}
198→			};
199→		});
200→	}
201→
202→	disconnect(): void {
203→		this.disposed = true;
204→		if (this.reconnectTimer) {
205→			clearTimeout(this.reconnectTimer);
206→			this.reconnectTimer = null;
207→		}
208→		if (this.ws) {
209→			this.ws.close(1000, "Client disconnecting");
210→			this.ws = null;
211→		}
212→	}
213→
214→	private scheduleReconnect(): void {
215→		if (this.disposed || this.reconnectTimer) return;
216→		const delay = Math.min(1000 * 2 ** this.reconnectAttempt, 30_000);
217→		this.reconnectAttempt++;
218→		this.reconnectTimer = setTimeout(() => {
219→			this.reconnectTimer = null;
220→			this.connect();
221→		}, delay);
222→	}
223→}
