  1→// ServerConnectionProvider — React context that owns RelayClient + QueryTransport.
  2→// Routes incoming q:* frames to QueryTransport. Components access connection via useServerConnection().
  3→
  4→import type { QueryClientFrame, QueryInvalidate, QueryServerFrame } from "@cancun/types";
  5→import { useQueryClient } from "@tanstack/react-query";
  6→import {
  7→	type ReactNode,
  8→	createContext,
  9→	useCallback,
 10→	useContext,
 11→	useEffect,
 12→	useRef,
 13→	useState,
 14→} from "react";
 15→import { RELAY_HTTP_URL, RELAY_WS_URL } from "./env";
 16→import { QueryTransport } from "./query-transport";
 17→import { RelayClient, type RelayStatus, type ServerOfflineInfo } from "./relay-client";
 18→import { addSavedServer, getSavedServers } from "./storage";
 19→
 20→// ── Types ───────────────────────────────────────────────
 21→
 22→export interface ServerConnectionValue {
 23→	connStatus: RelayStatus;
 24→	error: string | null;
 25→	serverName: string | null;
 26→	offlineInfo: ServerOfflineInfo | null;
 27→	transport: QueryTransport | null;
 28→	serverId: string;
 29→	reconnect: () => void;
 30→}
 31→
 32→const ServerConnectionContext = createContext<ServerConnectionValue | null>(null);
 33→
 34→// ── Provider ────────────────────────────────────────────
 35→
 36→export function ServerConnectionProvider({
 37→	serverId,
 38→	token,
 39→	children,
 40→}: {
 41→	serverId: string;
 42→	token: string;
 43→	children: ReactNode;
 44→}) {
 45→	const queryClient = useQueryClient();
 46→
 47→	const [connStatus, setConnStatus] = useState<RelayStatus>("disconnected");
 48→	const [error, setError] = useState<string | null>(null);
 49→	const [serverName, setServerName] = useState<string | null>(() => {
 50→		const saved = getSavedServers().find((s) => s.id === serverId);
 51→		return saved?.name || null;
 52→	});
 53→	const [offlineInfo, setOfflineInfo] = useState<ServerOfflineInfo | null>(null);
 54→
 55→	const transportRef = useRef<QueryTransport | null>(null);
 56→	const clientRef = useRef<RelayClient | null>(null);
 57→	const connStatusRef = useRef<RelayStatus>(connStatus);
 58→
 59→	// ── Route incoming messages ─────────────────────────
 60→
 61→	const handleMessage = useCallback(
 62→		(data: unknown) => {
 63→			const msg = data as Record<string, unknown>;
 64→			const type = msg.type as string;
 65→
 66→			// q:* frames → QueryTransport
 67→			if (type?.startsWith("q:")) {
 68→				if (type === "q:invalidate") {
 69→					const frame = msg as QueryInvalidate;
 70→					for (const resource of frame.resources) {
 71→						queryClient.invalidateQueries({ queryKey: ["server", serverId, resource] });
 72→					}
 73→					return;
 74→				}
 75→				transportRef.current?.handleServerFrame(msg as QueryServerFrame);
 76→				return;
 77→			}
 78→
 79→			// Server name from initial_state (still useful for display)
 80→			if (type === "initial_state") {
 81→				const state = msg as { serverName?: string };
 82→				if (state.serverName) {
 83→					setServerName(state.serverName);
 84→					addSavedServer(serverId, state.serverName);
 85→				}
 86→				return;
 87→			}
 88→		},
 89→		[serverId, queryClient],
 90→	);
 91→
 92→	// ── Initialize RelayClient + QueryTransport ─────────
 93→
 94→	useEffect(() => {
 95→		const sendFn: (frame: QueryClientFrame) => void = (frame) => clientRef.current?.send(frame);
 96→
 97→		const transport = new QueryTransport(sendFn);
 98→		transportRef.current = transport;
 99→
100→		const client = new RelayClient({
101→			relayUrl: RELAY_WS_URL,
102→			serverId,
103→			token,
104→			onStatusChange: (status) => {
105→				connStatusRef.current = status;
106→				setConnStatus(status);
107→				if (status === "connected") {
108→					setOfflineInfo(null);
109→					setError(null);
110→					transport.resubscribeAll(sendFn);
111→				}
112→				if (status === "disconnected" || status === "error") {
113→					transport.rejectAll("Disconnected");
114→				}
115→			},
116→			onMessage: handleMessage,
117→			onError: (err) => setError(err),
118→			onServerOffline: (info) => {
119→				setOfflineInfo(info);
120→				if (info?.serverName) setServerName(info.serverName);
121→			},
122→		});
123→
124→		clientRef.current = client;
125→		client.connect();
126→
127→		return () => {
128→			transport.destroy();
129→			client.disconnect();
130→			clientRef.current = null;
131→			transportRef.current = null;
132→		};
133→	}, [serverId, token, handleMessage]);
134→
135→	// ── Prefetch server status via HTTP ─────────────────
136→
137→	useEffect(() => {
138→		let cancelled = false;
139→		fetch(`${RELAY_HTTP_URL}/api/servers/${serverId}/status`)
140→			.then((r) => (r.ok ? r.json() : null))
141→			.then((data) => {
142→				if (cancelled || !data || connStatusRef.current === "connected") return;
143→				if (data.serverName) setServerName((prev) => prev ?? data.serverName);
144→				if (!data.online && data.serverDisconnectedAt) {
145→					setOfflineInfo({
146→						serverName: data.serverName || null,
147→						disconnectedAt: data.serverDisconnectedAt,
148→					});
149→				}
150→			})
151→			.catch((err) => console.warn("[prefetch] Server status check failed:", err.message));
152→		return () => {
153→			cancelled = true;
154→		};
155→	}, [serverId]);
156→
157→	// ── Context value ───────────────────────────────────
158→
159→	const value: ServerConnectionValue = {
160→		connStatus,
161→		error,
162→		serverName,
163→		offlineInfo,
164→		transport: transportRef.current,
165→		serverId,
166→		reconnect: () => clientRef.current?.connect(),
167→	};
168→
169→	return (
170→		<ServerConnectionContext.Provider value={value}>{children}</ServerConnectionContext.Provider>
171→	);
172→}
173→
174→// ── Hook ────────────────────────────────────────────────
175→
176→export function useServerConnection() {
177→	const ctx = useContext(ServerConnectionContext);
178→	if (!ctx) throw new Error("useServerConnection must be within ServerConnectionProvider");
179→	return ctx;
180→}
