  1→// QueryTransport — request correlation, subscriptions, and mutation handling.
  2→// Plain TypeScript class with no React dependency. Unit-testable with mock send functions.
  3→//
  4→// Phase 1: Created but not yet the primary data path (legacy bridge handles it).
  5→// Phase 2+: Becomes the primary transport when server supports q:* frames.
  6→
  7→import type {
  8→	MutationName,
  9→	MutationParams,
 10→	MutationResult,
 11→	QueryClientFrame,
 12→	QueryServerFrame,
 13→	ResourceName,
 14→} from "@cancun/types";
 15→
 16→type SendFn = (frame: QueryClientFrame) => void;
 17→
 18→type PendingRequest = {
 19→	resolve: (data: unknown) => void;
 20→	reject: (error: Error) => void;
 21→	timer: ReturnType<typeof setTimeout>;
 22→};
 23→
 24→type ActiveSubscription = {
 25→	resource: ResourceName;
 26→	params: Record<string, unknown>;
 27→	onSnapshot: (data: unknown) => void;
 28→	onDelta: (upserted?: unknown[], removed?: string[]) => void;
 29→};
 30→
 31→export class QueryTransport {
 32→	private send: SendFn;
 33→	private pending = new Map<string, PendingRequest>();
 34→	private subscriptions = new Map<string, ActiveSubscription>();
 35→	private counter = 0;
 36→	private timeoutMs = 10_000;
 37→
 38→	constructor(send: SendFn) {
 39→		this.send = send;
 40→	}
 41→
 42→	// ── One-shot query → Promise ────────────────────────
 43→
 44→	fetch(resource: ResourceName, params?: Record<string, unknown>): Promise<unknown> {
 45→		const id = `rq_${++this.counter}`;
 46→		return new Promise((resolve, reject) => {
 47→			const timer = setTimeout(() => {
 48→				this.pending.delete(id);
 49→				reject(new Error(`Query timeout: ${resource}`));
 50→			}, this.timeoutMs);
 51→
 52→			this.pending.set(id, { resolve, reject, timer });
 53→			this.send({ type: "q:request", id, resource, params });
 54→		});
 55→	}
 56→
 57→	// ── Subscribe → snapshot + deltas ───────────────────
 58→
 59→	subscribe(
 60→		resource: ResourceName,
 61→		params: Record<string, unknown>,
 62→		onSnapshot: (data: unknown) => void,
 63→		onDelta: (upserted?: unknown[], removed?: string[]) => void,
 64→	): () => void {
 65→		const id = `sub_${++this.counter}`;
 66→
 67→		this.subscriptions.set(id, { resource, params, onSnapshot, onDelta });
 68→		this.send({ type: "q:subscribe", id, resource, params });
 69→
 70→		return () => {
 71→			this.subscriptions.delete(id);
 72→			this.send({ type: "q:unsubscribe", id });
 73→		};
 74→	}
 75→
 76→	// ── Mutation → Promise (typed) ──────────────────────
 77→
 78→	mutate<M extends MutationName>(
 79→		action: M,
 80→		params: MutationParams<M>,
 81→	): Promise<{ success: boolean; data?: MutationResult<M>; error?: string }> {
 82→		const id = `mut_${++this.counter}`;
 83→		return new Promise((resolve, reject) => {
 84→			const timer = setTimeout(() => {
 85→				this.pending.delete(id);
 86→				reject(new Error(`Mutation timeout: ${action}`));
 87→			}, this.timeoutMs);
 88→
 89→			this.pending.set(id, {
 90→				resolve: (data) =>
 91→					resolve(data as { success: boolean; data?: MutationResult<M>; error?: string }),
 92→				reject,
 93→				timer,
 94→			});
 95→			this.send({ type: "q:mutate", id, action, params: params as Record<string, unknown> });
 96→		});
 97→	}
 98→
 99→	// ── Route incoming server frames ────────────────────
100→
101→	handleServerFrame(frame: QueryServerFrame): void {
102→		switch (frame.type) {
103→			case "q:response":
104→			case "q:mutate_result": {
105→				const pending = this.pending.get(frame.id);
106→				if (!pending) return;
107→				clearTimeout(pending.timer);
108→				this.pending.delete(frame.id);
109→				if (frame.type === "q:response") {
110→					pending.resolve(frame.data);
111→				} else {
112→					pending.resolve(frame);
113→				}
114→				break;
115→			}
116→
117→			case "q:error": {
118→				const pending = this.pending.get(frame.id);
119→				if (!pending) return;
120→				clearTimeout(pending.timer);
121→				this.pending.delete(frame.id);
122→				pending.reject(new Error(`${frame.code}: ${frame.message}`));
123→				break;
124→			}
125→
126→			case "q:snapshot": {
127→				const sub = this.subscriptions.get(frame.id);
128→				if (sub) sub.onSnapshot(frame.data);
129→				break;
130→			}
131→
132→			case "q:delta": {
133→				const sub = this.subscriptions.get(frame.id);
134→				if (sub) sub.onDelta(frame.upserted, frame.removed);
135→				break;
136→			}
