app.get("/api/servers/:serverId/connect", withRelay, async (c) => {
	const stub = c.get("stub");
	const connectUrl = new URL(c.req.url);
	connectUrl.pathname = "/connect";
	return stub.fetch(new Request(connectUrl, c.req.raw));
});

