  1→// Cloudflare Durable Object for relay WebSocket multiplexing.
  2→// One DO per Deus server. Holds the server tunnel + all client connections.
  3→// Uses the WebSocket Hibernation API for efficient connection handling.
  4→// All mutable state lives in ctx.storage to survive hibernation.
  5→//
  6→// Storage keys:
  7→//   relayToken                   — server's relay token (set on first registration)
  8→//   tunnelRegistered             — boolean, true after successful register handshake
  9→//   serverDisconnectedAt         — timestamp when server disconnected (persists until reconnect)
 10→//   pending:<clientId>           — auth deadline timestamp for pending clients
 11→//   auth_token:<clientId>        — client's device token (stored for re-forwarding on reconnect)
 12→//   pending:pair:<pairId>       — deadline timestamp for one-shot pairing requests
 13→
 14→import { DurableObject } from "cloudflare:workers";
 15→import type {
 16→	PairerFrame,
 17→	RelayClientFrame,
 18→	RelayFrame,
 19→	RelayPairerFrame,
 20→	ServerFrame,
 21→} from "@cancun/types";
 22→import { clientAuthFrameSchema, pairerFrameSchema, serverFrameSchema } from "@cancun/types";
 23→
 24→const AUTH_TIMEOUT_MS = 5_000;
 25→const OFFLINE_WAIT_MS = 300_000; // 5 min — max time a client waits for server to reconnect
 26→const HEARTBEAT_INTERVAL_MS = 30_000;
 27→const PAIR_TIMEOUT_MS = 30_000;
 28→
 29→export class RelayDO extends DurableObject {
 30→	async fetch(request: Request): Promise<Response> {
 31→		const url = new URL(request.url);
 32→
 33→		if (url.pathname === "/tunnel") {
 34→			return this.handleTunnel(request);
 35→		}
 36→		if (url.pathname === "/connect") {
 37→			return this.handleClient(request);
 38→		}
 39→		if (url.pathname === "/pair") {
 40→			return this.handlePairer(request);
 41→		}
 42→		if (url.pathname === "/status") {
 43→			return this.handleStatus();
 44→		}
 45→
 46→		return new Response("Not found", { status: 404 });
 47→	}
 48→
 49→	// ---- Server Tunnel ----
 50→
 51→	private async handleTunnel(request: Request): Promise<Response> {
 52→		// Authenticate BEFORE closing existing tunnels to prevent unauthenticated
 53→		// connections from disrupting a legitimate server's tunnel (DoS).
 54→		const storedToken = await this.ctx.storage.get<string>("relayToken");
 55→		if (storedToken) {
 56→			const url = new URL(request.url);
 57→			const token =
 58→				request.headers.get("Authorization")?.replace("Bearer ", "") ||
 59→				url.searchParams.get("token");
 60→			if (token !== storedToken) {
 61→				return new Response("Unauthorized", { status: 401 });
 62→			}
 63→		}
 64→
 65→		// Close any existing tunnel before accepting a new one to prevent
 66→		// stale connections from receiving messages meant for the new tunnel.
 67→		const existingTunnels = this.ctx.getWebSockets("tunnel");
 68→		for (const tunnel of existingTunnels) {
 69→			try {
 70→				tunnel.close(1000, "New tunnel connection");
 71→			} catch (err) {
 72→				console.error("relay: failed to close existing tunnel", err);
 73→			}
 74→		}
 75→
 76→		// New tunnel is not yet registered — must complete register handshake first
 77→		await this.ctx.storage.put("tunnelRegistered", false);
 78→
 79→		const pair = new WebSocketPair();
 80→		const [client, server] = Object.values(pair) as [WebSocket, WebSocket];
 81→
 82→		this.ctx.acceptWebSocket(server, ["tunnel"]);
 83→
 84→		return new Response(null, { status: 101, webSocket: client });
 85→	}
 86→
 87→	// ---- Client Connection ----
 88→
 89→	private async handleClient(_request: Request): Promise<Response> {
 90→		const tunnels = this.ctx.getWebSockets("tunnel");
 91→		if (tunnels.length === 0) {
 92→			// Accept connections if server was ever registered — it may come back.
 93→			// Only reject for completely unknown servers (never registered).
 94→			const hasEverRegistered = await this.ctx.storage.get<string>("relayToken");
 95→			if (!hasEverRegistered) {
 96→				return Response.json({ error: "server_not_found" }, { status: 503 });
 97→			}
 98→		}
 99→
100→		const pair = new WebSocketPair();
101→		const [client, server] = Object.values(pair) as [WebSocket, WebSocket];
102→
103→		const clientId = crypto.randomUUID();
104→		// Tags are immutable after acceptWebSocket — don't encode mutable state in them.
105→		// Auth state is tracked via storage keys instead.
106→		this.ctx.acceptWebSocket(server, ["client", clientId]);
107→
108→		// Store auth deadline in durable storage (survives hibernation)
109→		await this.ctx.storage.put(`pending:${clientId}`, Date.now() + AUTH_TIMEOUT_MS);
110→		await this.scheduleNextAlarm();
111→
112→		return new Response(null, { status: 101, webSocket: client });
113→	}
114→
115→	// ---- Status ----
116→
117→	private async handleStatus(): Promise<Response> {
118→		const tunnels = this.ctx.getWebSockets("tunnel");
119→		const allClients = this.ctx.getWebSockets("client");
120→		const pendingClientCount = (await this.getPendingClients()).size;
121→		const serverDisconnectedAt = await this.ctx.storage.get<number>("serverDisconnectedAt");
122→		const serverName = await this.ctx.storage.get<string>("serverName");
123→
124→		return Response.json({
125→			online: tunnels.length > 0,
126→			clients: Math.max(0, allClients.length - pendingClientCount),
127→			reconnecting: serverDisconnectedAt !== undefined,
128→			serverDisconnectedAt: serverDisconnectedAt ?? null,
129→			serverName: serverName || null,
130→		});
131→	}
132→
133→	// ---- Pairing (one-shot code exchange) ----
134→
135→	private async handlePairer(_request: Request): Promise<Response> {
136→		// Pairing requires an active, registered server tunnel
137→		const tunnel = this.getTunnel();
138→		const isRegistered = await this.ctx.storage.get<boolean>("tunnelRegistered");
139→		if (!tunnel || !isRegistered) {
140→			return Response.json({ error: "server_offline" }, { status: 503 });
141→		}
142→
143→		const pair = new WebSocketPair();
144→		const [client, server] = Object.values(pair) as [WebSocket, WebSocket];
145→
146→		const pairId = crypto.randomUUID();
147→		this.ctx.acceptWebSocket(server, ["pairer", pairId]);
148→
149→		// Store deadline for cleanup via alarm
150→		await this.ctx.storage.put(`pending:pair:${pairId}`, Date.now() + PAIR_TIMEOUT_MS);
151→		await this.scheduleNextAlarm();
152→
153→		return new Response(null, { status: 101, webSocket: client });
154→	}
155→
156→	// ---- WebSocket Handlers (Hibernation API) ----
157→
158→	async webSocketMessage(ws: WebSocket, message: string | ArrayBuffer): Promise<void> {
159→		const tags = this.ctx.getTags(ws);
160→		const raw = typeof message === "string" ? message : new TextDecoder().decode(message);
161→
162→		let json: unknown;
163→		try {
164→			json = JSON.parse(raw);
165→		} catch {
166→			console.error("relay: failed to parse WebSocket message as JSON");
167→			return;
168→		}
169→
170→		if (tags.includes("tunnel")) {
171→			const result = serverFrameSchema.safeParse(json);
172→			if (!result.success) {
173→				console.error("relay: invalid server frame", result.error.issues);
174→				return;
175→			}
176→			await this.handleServerMessage(ws, result.data);
177→		} else if (tags.includes("pairer")) {
178→			const pairId = tags.find((t) => t !== "pairer");
179→			if (!pairId) return;
180→			const result = pairerFrameSchema.safeParse(json);
181→			if (!result.success) {
182→				console.error("relay: invalid pairer frame", result.error.issues);
183→				return;
184→			}
185→			await this.handlePairerMessage(pairId, result.data);
186→		} else if (tags.includes("client")) {
187→			const clientId = tags.find((t) => t !== "client");
188→			if (!clientId) return;
189→			await this.handleClientMessage(clientId, json);
190→		}
191→	}
192→
193→	async webSocketClose(
194→		ws: WebSocket,
195→		_code: number,
196→		_reason: string,
197→		_wasClean: boolean,
198→	): Promise<void> {
199→		const tags = this.ctx.getTags(ws);
200→
201→		if (tags.includes("tunnel")) {
202→			await this.handleServerDisconnect();
203→		} else if (tags.includes("pairer")) {
204→			const pairId = tags.find((t) => t !== "pairer");
205→			if (pairId) {
206→				await this.ctx.storage.delete(`pending:pair:${pairId}`);
207→			}
208→		} else if (tags.includes("client")) {
209→			const clientId = tags.find((t) => t !== "client");
210→			if (clientId) {
211→				await this.handleClientDisconnect(clientId);
212→			}
213→		}
214→	}
215→
216→	async webSocketError(ws: WebSocket, _error: unknown): Promise<void> {
217→		const tags = this.ctx.getTags(ws);
218→
219→		if (tags.includes("tunnel")) {
220→			await this.handleServerDisconnect();
221→		} else if (tags.includes("pairer")) {
222→			const pairId = tags.find((t) => t !== "pairer");
223→			if (pairId) {
224→				await this.ctx.storage.delete(`pending:pair:${pairId}`);
225→			}
226→		} else if (tags.includes("client")) {
227→			const clientId = tags.find((t) => t !== "client");
228→			if (clientId) {
229→				await this.handleClientDisconnect(clientId);
230→			}
231→		}
232→	}
233→
234→	// ---- Alarm (auth timeout + heartbeat) ----
235→
236→	async alarm(): Promise<void> {
237→		const now = Date.now();
238→
239→		// 1. Reject clients whose auth deadline has expired
240→		const pendingClients = await this.getPendingClients();
241→		const expiredClientIds: string[] = [];
242→		for (const [clientId, deadline] of pendingClients) {
243→			if (now >= deadline) {
244→				expiredClientIds.push(clientId);
245→			}
246→		}
247→		if (expiredClientIds.length > 0) {
248→			const keysToDelete = expiredClientIds.flatMap((id) => [`pending:${id}`, `auth_token:${id}`]);
249→			await this.ctx.storage.delete(keysToDelete);
250→			for (const clientId of expiredClientIds) {
251→				this.rejectClient(clientId, "Authentication timeout");
252→			}
253→		}
254→
255→		// 1b. Reject pairers whose deadline has expired
256→		const pendingPairs = await this.ctx.storage.list<number>({ prefix: "pending:pair:" });
257→		for (const [key, deadline] of pendingPairs) {
258→			if (now >= deadline) {
259→				const pairId = key.slice("pending:pair:".length);
260→				const pairerWs = this.findPairerWs(pairId);
261→				if (pairerWs) {
262→					this.safeSend(pairerWs, { type: "pair_failed", message: "Pairing timed out" });
263→					try {
264→						pairerWs.close(1000, "Pairing timed out");
265→					} catch (err) {
266→						console.error("relay: failed to close expired pairer", err);
267→					}
268→				}
269→				await this.ctx.storage.delete(key);
270→			}
271→		}
272→
273→		// 2. Send heartbeat ping to server
274→		const tunnel = this.getTunnel();
275→		if (tunnel) {
276→			this.safeSend(tunnel, { type: "ping" });
277→		}
278→
279→		// 3. Reschedule for next event
280→		await this.scheduleNextAlarm();
281→	}
282→
283→	// ---- Server Message Handling ----
284→
285→	private async handleServerMessage(ws: WebSocket, frame: ServerFrame): Promise<void> {
286→		const isRegistered = await this.ctx.storage.get<boolean>("tunnelRegistered");
287→
288→		switch (frame.type) {
289→			case "register": {
290→				await this.handleRegister(ws, frame);
291→				break;
292→			}
293→			case "auth_response": {
294→				// Only registered tunnels may send auth_response
295→				if (!isRegistered) break;
296→				await this.handleAuthResponse(frame.clientId, frame.allowed, frame.reason);
297→				break;
298→			}
299→			case "pair_response": {
300→				if (!isRegistered) break;
301→				await this.ctx.storage.delete(`pending:pair:${frame.pairId}`);
302→				const pairerWs = this.findPairerWs(frame.pairId);
303→				if (!pairerWs) break;
304→				if (frame.success && frame.deviceToken) {
305→					this.safeSend(pairerWs, { type: "pair_success", token: frame.deviceToken });
306→				} else {
307→					this.safeSend(pairerWs, {
308→						type: "pair_failed",
309→						message: frame.reason || "Pairing failed",
310→					});
311→				}
312→				// Close the one-shot pairer WS — buffered messages are sent before the close frame
313→				try {
314→					pairerWs.close(1000, "Pairing complete");
315→				} catch (err) {
316→					console.error("relay: failed to close pairer after response", err);
317→				}
318→				break;
319→			}
320→			case "data": {
321→				// Only registered tunnels may send data
322→				if (!isRegistered) break;
323→				await this.forwardToClient(frame.clientId, frame.payload);
324→				break;
325→			}
326→			case "pong": {
327→				break;
328→			}
329→		}
330→	}
331→
332→	private async handleRegister(
333→		ws: WebSocket,
334→		frame: Extract<ServerFrame, { type: "register" }>,
335→	): Promise<void> {
336→		const storedToken = await this.ctx.storage.get<string>("relayToken");
337→		if (storedToken && storedToken !== frame.relayToken) {
338→			this.safeSend(ws, { type: "error", message: "Invalid relay token" });
339→			try {
340→				ws.close(4003, "Invalid relay token");
341→			} catch (err) {
342→				console.error("relay: failed to close tunnel with bad token", err);
343→			}
344→			return;
345→		}
346→
347→		if (!storedToken) {
348→			await this.ctx.storage.put("relayToken", frame.relayToken);
349→		}
350→
351→		// Always update server name (user might have changed it)
352→		if (frame.serverName) {
353→			await this.ctx.storage.put("serverName", frame.serverName);
354→		}
355→
356→		// Mark tunnel as registered — gates auth_response/data processing
357→		await this.ctx.storage.put("tunnelRegistered", true);
358→
359→		// Clear reconnection state and notify clients server is back
360→		const wasReconnecting = await this.ctx.storage.get<number>("serverDisconnectedAt");
361→		await this.ctx.storage.delete("serverDisconnectedAt");
362→
363→		// Confirm registration to the WebSocket that sent it
364→		this.safeSend(ws, { type: "registered" });
365→
366→		// Notify already-authenticated clients that the server is back.
367→		// Pending clients are notified via the normal auth flow (they'll get "authenticated").
368→		if (wasReconnecting !== undefined) {
369→			const clients = this.ctx.getWebSockets("client");
370→			for (const clientWs of clients) {
371→				const clientId = this.ctx.getTags(clientWs).find((t) => t !== "client");
372→				if (!clientId) continue;
373→				const isPending = await this.ctx.storage.get<number>(`pending:${clientId}`);
374→				if (isPending !== undefined) continue;
375→				this.safeSend(clientWs, { type: "server_connected" });
376→			}
377→		}
378→
379→		// Always re-forward pending clients' stored auth tokens to the new tunnel.
380→		// This handles both reconnection (wasReconnecting) and tunnel replacement
381→		// (where serverDisconnectedAt was never set because the old tunnel's close
382→		// handler saw the new tunnel already existed).
383→		const pendingClients = await this.getPendingClients();
384→		for (const [pendingClientId] of pendingClients) {
385→			const storedAuthToken = await this.ctx.storage.get<string>(`auth_token:${pendingClientId}`);
386→			if (storedAuthToken) {
387→				this.safeSend(ws, {
388→					type: "client_connected",
389→					clientId: pendingClientId,
390→					deviceToken: storedAuthToken,
391→				});
392→			}
393→		}
394→
395→		// Start heartbeat
396→		await this.scheduleNextAlarm();
397→	}
398→
399→	// ---- Auth Delegation ----
400→
401→	private async handleAuthResponse(
402→		clientId: string,
403→		allowed: boolean,
404→		reason?: string,
405→	): Promise<void> {
406→		await this.ctx.storage.delete(`pending:${clientId}`);
407→		await this.ctx.storage.delete(`auth_token:${clientId}`);
408→
409→		if (allowed) {
410→			this.activateClient(clientId);
411→		} else {
412→			this.rejectClient(clientId, reason || "Authentication denied");
413→		}
414→	}
415→
416→	private activateClient(clientId: string): void {
417→		const ws = this.findClientWs(clientId);
418→		if (ws) {
419→			this.safeSend(ws, { type: "authenticated" });
420→		}
421→	}
422→
423→	private rejectClient(clientId: string, message: string): void {
424→		const ws = this.findClientWs(clientId);
425→		if (ws) {
426→			this.safeSend(ws, { type: "auth_failed", message });
427→			try {
428→				ws.close(4003, message);
429→			} catch (err) {
430→				console.error(`relay: failed to close rejected client ${clientId}`, err);
431→			}
432→		}
433→	}
434→
435→	// ---- Client Message Handling ----
436→
437→	private async handleClientMessage(clientId: string, json: unknown): Promise<void> {
438→		const isPending = await this.ctx.storage.get<number>(`pending:${clientId}`);
439→
440→		if (isPending !== undefined) {
441→			// Client is still pending — only accept authenticate messages
442→			const authResult = clientAuthFrameSchema.safeParse(json);
443→			if (!authResult.success) return;
444→
445→			const { token } = authResult.data;
446→			// Store the token so we can re-forward it if the server reconnects
447→			await this.ctx.storage.put(`auth_token:${clientId}`, token);
448→
449→			const tunnel = this.getTunnel();
450→			const isRegistered = await this.ctx.storage.get<boolean>("tunnelRegistered");
451→			if (tunnel && isRegistered) {
452→				this.safeSend(tunnel, {
453→					type: "client_connected",
454→					clientId,
455→					deviceToken: token,
456→				});
457→			} else if (tunnel) {
458→				// Tunnel exists but not yet registered — replacement in progress.
459→				// Leave client pending; handleRegister will re-forward the stored
460→				// auth token once the new tunnel completes registration.
461→				// The auth timeout alarm will reject naturally if registration never comes.
462→			} else {
463→				// Server tunnel is down — keep client waiting for server to return.
464→				// Suspend the short auth deadline; handleRegister will re-forward the
465→				// stored auth token when the server reconnects.
466→				const serverDisconnectedAt = await this.ctx.storage.get<number>("serverDisconnectedAt");
467→				await this.ctx.storage.put(`pending:${clientId}`, Date.now() + OFFLINE_WAIT_MS);
468→				const clientWs = this.findClientWs(clientId);
469→				if (clientWs) {
470→					const serverName = await this.ctx.storage.get<string>("serverName");
471→					this.safeSend(clientWs, {
472→						type: "server_reconnecting",
473→						serverDisconnectedAt: serverDisconnectedAt ?? Date.now(),
474→						serverName: serverName || null,
475→					});
476→				}
477→			}
478→			return;
479→		}
480→
481→		// Authenticated client — forward data to server
482→		const tunnel = this.getTunnel();
483→		if (tunnel) {
484→			this.safeSend(tunnel, {
485→				type: "data",
486→				clientId,
487→				payload: JSON.stringify(json),
488→			});
489→		}
490→	}
491→
492→	// ---- Pairer Message Handling ----
493→
494→	private async handlePairerMessage(pairId: string, frame: PairerFrame): Promise<void> {
495→		const isPending = await this.ctx.storage.get<number>(`pending:pair:${pairId}`);
496→		if (isPending === undefined) return;
497→
498→		const tunnel = this.getTunnel();
499→		const isRegistered = await this.ctx.storage.get<boolean>("tunnelRegistered");
500→		if (tunnel && isRegistered) {
501→			this.safeSend(tunnel, {
502→				type: "pair_request",
503→				pairId,
504→				code: frame.code,
505→				deviceName: frame.deviceName,
506→			});
507→		} else {
508→			const pairerWs = this.findPairerWs(pairId);
509→			if (pairerWs) {
510→				this.safeSend(pairerWs, { type: "pair_failed", message: "Server is offline" });
511→				try {
512→					pairerWs.close(1000, "Server offline");
513→				} catch (err) {
514→					console.error("relay: failed to close pairer (server offline)", err);
515→				}
516→			}
517→			await this.ctx.storage.delete(`pending:pair:${pairId}`);
518→		}
519→	}
520→
521→	// ---- Client/Server Lifecycle ----
522→
523→	private async handleClientDisconnect(clientId: string): Promise<void> {
524→		await this.ctx.storage.delete(`pending:${clientId}`);
525→		await this.ctx.storage.delete(`auth_token:${clientId}`);
526→
527→		const tunnel = this.getTunnel();
528→		if (tunnel) {
529→			this.safeSend(tunnel, {
530→				type: "client_disconnected",
531→				clientId,
532→			});
533→		}
534→	}
535→
536→	private async handleServerDisconnect(): Promise<void> {
537→		// If another tunnel is already active (e.g. old tunnel's close callback firing
538→		// after handleTunnel replaced it), skip the disconnect flow.
539→		const tunnels = this.ctx.getWebSockets("tunnel");
540→		if (tunnels.length > 0) return;
541→
542→		const existing = await this.ctx.storage.get<number>("serverDisconnectedAt");
543→		if (existing !== undefined) return; // Already handling disconnect
544→
545→		await this.ctx.storage.put("tunnelRegistered", false);
546→		const disconnectedAt = Date.now();
547→		await this.ctx.storage.put("serverDisconnectedAt", disconnectedAt);
548→
549→		const serverName = await this.ctx.storage.get<string>("serverName");
550→		const clients = this.ctx.getWebSockets("client");
551→		for (const clientWs of clients) {
552→			this.safeSend(clientWs, {
553→				type: "server_reconnecting",
554→				serverDisconnectedAt: disconnectedAt,
555→				serverName: serverName || null,
556→			});
557→		}
558→
559→		await this.scheduleNextAlarm();
560→	}
561→
562→	// ---- Data Forwarding ----
563→
564→	private async forwardToClient(clientId: string, payload: string): Promise<void> {
565→		const isPending = await this.ctx.storage.get<number>(`pending:${clientId}`);
566→		if (isPending !== undefined) {
567→			return;
568→		}
569→
570→		const ws = this.findClientWs(clientId);
571→		if (ws) {
572→			try {
573→				ws.send(payload);
574→			} catch (err) {
575→				console.error(`relay: failed to forward data to client ${clientId}`, err);
576→			}
577→		}
578→	}
579→
580→	// ---- Alarm Scheduling ----
581→
582→	private async scheduleNextAlarm(): Promise<void> {
583→		const now = Date.now();
584→		const candidates: number[] = [];
585→
586→		// Earliest pending auth deadline
587→		const pendingClients = await this.ctx.storage.list<number>({ prefix: "pending:" });
588→		for (const [, deadline] of pendingClients) {
589→			candidates.push(deadline);
590→		}
591→
592→		// Earliest pending pair deadline
593→		const pendingPairs = await this.ctx.storage.list<number>({ prefix: "pending:pair:" });
594→		for (const [, deadline] of pendingPairs) {
595→			candidates.push(deadline);
596→		}
597→
598→		// Heartbeat interval (only if server is connected)
599→		const tunnels = this.ctx.getWebSockets("tunnel");
600→		if (tunnels.length > 0) {
601→			candidates.push(now + HEARTBEAT_INTERVAL_MS);
602→		}
603→
604→		if (candidates.length > 0) {
605→			const nextAlarm = Math.min(...candidates);
606→			// Ensure alarm is at least 100ms in the future
607→			await this.ctx.storage.setAlarm(Math.max(nextAlarm, now + 100));
608→		}
609→	}
610→
611→	// ---- Helpers ----
612→
613→	/** Get pending client auth entries, filtering out pair entries that share the prefix. */
614→	private async getPendingClients(): Promise<Map<string, number>> {
615→		const entries = await this.ctx.storage.list<number>({ prefix: "pending:" });
616→		const result = new Map<string, number>();
617→		for (const [key, deadline] of entries) {
618→			if (key.startsWith("pending:pair:")) continue;
619→			result.set(key.slice("pending:".length), deadline);
620→		}
621→		return result;
622→	}
623→
624→	private findClientWs(clientId: string): WebSocket | null {
625→		const allClients = this.ctx.getWebSockets("client");
626→		for (const ws of allClients) {
627→			const tags = this.ctx.getTags(ws);
628→			if (tags.includes(clientId)) return ws;
629→		}
630→		return null;
631→	}
632→
633→	private findPairerWs(pairId: string): WebSocket | null {
634→		const allPairers = this.ctx.getWebSockets("pairer");
635→		for (const ws of allPairers) {
636→			const tags = this.ctx.getTags(ws);
637→			if (tags.includes(pairId)) return ws;
638→		}
639→		return null;
640→	}
641→
642→	private getTunnel(): WebSocket | null {
643→		const tunnels = this.ctx.getWebSockets("tunnel");
644→		return tunnels[0] ?? null;
645→	}
646→
647→	private safeSend(ws: WebSocket, data: RelayFrame | RelayClientFrame | RelayPairerFrame): void {
648→		try {
649→			ws.send(JSON.stringify(data));
650→		} catch (err) {
651→			console.error("relay: safeSend failed", err);
652→		}
653→	}
654→}
