  1→/**
  2→ * Auto-Updater
  3→ *
  4→ * Uses electron-updater to check for updates on GitHub Releases.
  5→ * Sends update state to the renderer via webContents.send so the
  6→ * frontend can show update toasts.
  7→ */
  8→
  9→import { type BrowserWindow, ipcMain } from "electron";
 10→import { autoUpdater, type UpdateInfo, type ProgressInfo } from "electron-updater";
 11→
 12→export type UpdateState =
 13→  | { status: "idle" }
 14→  | { status: "checking" }
 15→  | { status: "available"; info: UpdateInfo }
 16→  | { status: "not-available" }
 17→  | { status: "downloading"; progress: ProgressInfo }
 18→  | { status: "downloaded"; info: UpdateInfo }
 19→  | { status: "error"; error: string };
 20→
 21→let currentState: UpdateState = { status: "idle" };
 22→
 23→function sendState(win: BrowserWindow, state: UpdateState): void {
 24→  currentState = state;
 25→  if (win.isDestroyed() || win.webContents.isDestroyed()) return;
 26→  win.webContents.send("update:state", state);
 27→}
 28→
 29→export function setupAutoUpdater(mainWindow: BrowserWindow): void {
 30→  autoUpdater.autoDownload = false;
 31→  autoUpdater.autoInstallOnAppQuit = true;
 32→
 33→  autoUpdater.on("checking-for-update", () => {
 34→    sendState(mainWindow, { status: "checking" });
 35→  });
 36→
 37→  autoUpdater.on("update-available", (info) => {
 38→    sendState(mainWindow, { status: "available", info });
 39→  });
 40→
 41→  autoUpdater.on("update-not-available", () => {
 42→    sendState(mainWindow, { status: "not-available" });
 43→  });
 44→
 45→  autoUpdater.on("download-progress", (progress) => {
 46→    sendState(mainWindow, { status: "downloading", progress });
 47→  });
 48→
 49→  autoUpdater.on("update-downloaded", (info) => {
 50→    sendState(mainWindow, { status: "downloaded", info });
 51→  });
 52→
 53→  autoUpdater.on("error", (err) => {
 54→    sendState(mainWindow, { status: "error", error: err.message });
 55→  });
 56→
 57→  // IPC handlers for renderer to control updates
 58→
 59→  ipcMain.handle("update:check", async () => {
 60→    try {
 61→      const result = await autoUpdater.checkForUpdates();
 62→      return result ? { updateInfo: result.updateInfo } : null;
 63→    } catch (err) {
 64→      console.error("[auto-updater] Check failed:", err);
 65→      return null;
 66→    }
 67→  });
 68→
 69→  ipcMain.handle("update:download", async () => {
 70→    try {
 71→      await autoUpdater.downloadUpdate();
 72→    } catch (err) {
 73→      console.error("[auto-updater] Download failed:", err);
 74→    }
 75→  });
 76→
 77→  ipcMain.handle("update:install", () => {
 78→    autoUpdater.quitAndInstall(false, true);
 79→  });
 80→
 81→  ipcMain.handle("update:getState", () => {
 82→    return currentState;
 83→  });
 84→
 85→  // Initial check after 15s delay (called from main/index.ts)
 86→  autoUpdater.checkForUpdates().catch((err) => {
 87→    console.error("[auto-updater] Initial check failed:", err);
 88→  });
 89→
 90→  // Periodic check every 4 hours
 91→  setInterval(
 92→    () => {
 93→      autoUpdater.checkForUpdates().catch((err) => {
 94→        console.error("[auto-updater] Periodic check failed:", err);
 95→      });
 96→    },
 97→    4 * 60 * 60 * 1000
 98→  );
 99→}
