  1→// Cloudflare Durable Object for relay WebSocket multiplexing.
  2→// One DO per OpenDevs server. Holds the server tunnel + all client connections.
  3→// Uses the WebSocket Hibernation API for efficient connection handling.
  4→// All mutable state lives in ctx.storage to survive hibernation.
  5→//
  6→// Storage keys:
  7→//   relayToken                   — server's relay token (set on first registration)
  8→//   tunnelRegistered             — boolean, true after successful register handshake
  9→//   serverDisconnectedAt         — timestamp when server disconnected (persists until reconnect)
 10→//   serverName                   — server name for display to clients
 11→//   pending:<clientId>           — auth deadline timestamp for pending clients
 12→//   auth_token:<clientId>        — client's device token (stored for re-forwarding on reconnect)
 13→//   pending:pair:<pairId>       — deadline timestamp for one-shot pairing requests
 14→
 15→import { DurableObject } from "cloudflare:workers";
 16→import type {
 17→  PairerFrame,
 18→  RelayClientFrame,
 19→  RelayFrame,
 20→  RelayPairerFrame,
 21→  ServerFrame,
 22→} from "../../../shared/types/relay";
 23→import { clientAuthFrameSchema, pairerFrameSchema, serverFrameSchema } from "./schemas";
 24→
 25→const AUTH_TIMEOUT_MS = 5_000;
 26→const OFFLINE_WAIT_MS = 300_000; // 5 min — max time a client waits for server to reconnect
 27→const HEARTBEAT_INTERVAL_MS = 30_000;
 28→const PAIR_TIMEOUT_MS = 30_000;
 29→
 30→export class RelayDO extends DurableObject {
 31→  async fetch(request: Request): Promise<Response> {
 32→    const url = new URL(request.url);
 33→
 34→    if (url.pathname === "/tunnel") {
 35→      return this.handleTunnel(request);
 36→    }
 37→    if (url.pathname === "/connect") {
 38→      return this.handleClient(request);
 39→    }
 40→    if (url.pathname === "/pair") {
 41→      return this.handlePairer(request);
 42→    }
 43→    if (url.pathname === "/status") {
 44→      return this.handleStatus();
 45→    }
 46→
 47→    return new Response("Not found", { status: 404 });
 48→  }
 49→
 50→  // ---- Server Tunnel ----
 51→
 52→  private async handleTunnel(request: Request): Promise<Response> {
 53→    // Authenticate BEFORE closing existing tunnels to prevent unauthenticated
 54→    // connections from disrupting a legitimate server's tunnel (DoS).
 55→    const storedToken = await this.ctx.storage.get<string>("relayToken");
 56→    if (storedToken) {
 57→      const url = new URL(request.url);
 58→      const token =
 59→        request.headers.get("Authorization")?.replace("Bearer ", "") ||
 60→        url.searchParams.get("token");
 61→      if (token !== storedToken) {
 62→        return new Response("Unauthorized", { status: 401 });
 63→      }
 64→    }
 65→
 66→    // Close any existing tunnel before accepting a new one to prevent
 67→    // stale connections from receiving messages meant for the new tunnel.
 68→    const existingTunnels = this.ctx.getWebSockets("tunnel");
 69→    for (const tunnel of existingTunnels) {
 70→      try {
 71→        tunnel.close(1000, "New tunnel connection");
 72→      } catch (err) {
 73→        console.error("relay: failed to close existing tunnel", err);
 74→      }
 75→    }
 76→
 77→    // New tunnel is not yet registered — must complete register handshake first
 78→    await this.ctx.storage.put("tunnelRegistered", false);
 79→
 80→    const pair = new WebSocketPair();
 81→    const [client, server] = Object.values(pair) as [WebSocket, WebSocket];
 82→
 83→    this.ctx.acceptWebSocket(server, ["tunnel"]);
 84→
 85→    return new Response(null, { status: 101, webSocket: client });
 86→  }
 87→
 88→  // ---- Client Connection ----
 89→
 90→  private async handleClient(_request: Request): Promise<Response> {
 91→    const tunnels = this.ctx.getWebSockets("tunnel");
 92→    if (tunnels.length === 0) {
 93→      // Accept connections if server was ever registered — it may come back.
 94→      // Only reject for completely unknown servers (never registered).
 95→      const hasEverRegistered = await this.ctx.storage.get<string>("relayToken");
 96→      if (!hasEverRegistered) {
 97→        return Response.json({ error: "server_not_found" }, { status: 503 });
 98→      }
 99→    }
100→
101→    const pair = new WebSocketPair();
102→    const [client, server] = Object.values(pair) as [WebSocket, WebSocket];
103→
104→    const clientId = crypto.randomUUID();
105→    // Tags are immutable after acceptWebSocket — don't encode mutable state in them.
106→    // Auth state is tracked via storage keys instead.
107→    this.ctx.acceptWebSocket(server, ["client", clientId]);
108→
109→    // Store auth deadline in durable storage (survives hibernation)
110→    await this.ctx.storage.put(`pending:${clientId}`, Date.now() + AUTH_TIMEOUT_MS);
111→    await this.scheduleNextAlarm();
112→
113→    return new Response(null, { status: 101, webSocket: client });
114→  }
115→
116→  // ---- Status ----
117→
118→  private async handleStatus(): Promise<Response> {
119→    const tunnels = this.ctx.getWebSockets("tunnel");
120→    const allClients = this.ctx.getWebSockets("client");
121→    const pendingClientCount = (await this.getPendingClients()).size;
122→    const serverDisconnectedAt = await this.ctx.storage.get<number>("serverDisconnectedAt");
123→    const serverName = await this.ctx.storage.get<string>("serverName");
124→
125→    return Response.json({
126→      online: tunnels.length > 0,
127→      clients: Math.max(0, allClients.length - pendingClientCount),
128→      reconnecting: serverDisconnectedAt !== undefined,
129→      serverDisconnectedAt: serverDisconnectedAt ?? null,
130→      serverName: serverName || null,
131→    });
132→  }
133→
134→  // ---- Pairing (one-shot code exchange) ----
135→
136→  private async handlePairer(_request: Request): Promise<Response> {
137→    // Pairing requires an active, registered server tunnel
138→    const tunnel = this.getTunnel();
139→    const isRegistered = await this.ctx.storage.get<boolean>("tunnelRegistered");
140→    if (!tunnel || !isRegistered) {
141→      return Response.json({ error: "server_offline" }, { status: 503 });
142→    }
143→
144→    const pair = new WebSocketPair();
145→    const [client, server] = Object.values(pair) as [WebSocket, WebSocket];
146→
147→    const pairId = crypto.randomUUID();
148→    this.ctx.acceptWebSocket(server, ["pairer", pairId]);
149→
150→    // Store deadline for cleanup via alarm
151→    await this.ctx.storage.put(`pending:pair:${pairId}`, Date.now() + PAIR_TIMEOUT_MS);
152→    await this.scheduleNextAlarm();
153→
154→    return new Response(null, { status: 101, webSocket: client });
155→  }
156→
157→  // ---- WebSocket Handlers (Hibernation API) ----
158→
159→  async webSocketMessage(ws: WebSocket, message: string | ArrayBuffer): Promise<void> {
160→    const tags = this.ctx.getTags(ws);
161→    const raw = typeof message === "string" ? message : new TextDecoder().decode(message);
162→
163→    let json: unknown;
164→    try {
165→      json = JSON.parse(raw);
166→    } catch {
167→      console.error("relay: failed to parse WebSocket message as JSON");
168→      return;
169→    }
170→
171→    if (tags.includes("tunnel")) {
172→      const result = serverFrameSchema.safeParse(json);
173→      if (!result.success) {
174→        console.error("relay: invalid server frame", result.error.issues);
175→        return;
176→      }
177→      // Cast is safe — Zod validated the shape, but its inferred type for pair_response
178→      // uses `success: boolean` while our ServerFrame uses discriminated `true | false`.
179→      await this.handleServerMessage(ws, result.data as ServerFrame);
180→    } else if (tags.includes("pairer")) {
181→      const pairId = tags.find((t) => t !== "pairer");
182→      if (!pairId) return;
183→      const result = pairerFrameSchema.safeParse(json);
184→      if (!result.success) {
185→        console.error("relay: invalid pairer frame", result.error.issues);
186→        return;
187→      }
188→      await this.handlePairerMessage(pairId, result.data);
189→    } else if (tags.includes("client")) {
190→      const clientId = tags.find((t) => t !== "client");
191→      if (!clientId) return;
192→      await this.handleClientMessage(clientId, json);
193→    }
194→  }
195→
196→  async webSocketClose(
197→    ws: WebSocket,
198→    _code: number,
199→    _reason: string,
200→    _wasClean: boolean
201→  ): Promise<void> {
202→    const tags = this.ctx.getTags(ws);
203→
204→    if (tags.includes("tunnel")) {
205→      await this.handleServerDisconnect();
206→    } else if (tags.includes("pairer")) {
207→      const pairId = tags.find((t) => t !== "pairer");
208→      if (pairId) {
209→        await this.ctx.storage.delete(`pending:pair:${pairId}`);
210→      }
211→    } else if (tags.includes("client")) {
212→      const clientId = tags.find((t) => t !== "client");
213→      if (clientId) {
214→        await this.handleClientDisconnect(clientId);
215→      }
216→    }
217→  }
218→
219→  async webSocketError(ws: WebSocket, _error: unknown): Promise<void> {
220→    const tags = this.ctx.getTags(ws);
221→
222→    if (tags.includes("tunnel")) {
223→      await this.handleServerDisconnect();
224→    } else if (tags.includes("pairer")) {
225→      const pairId = tags.find((t) => t !== "pairer");
226→      if (pairId) {
227→        await this.ctx.storage.delete(`pending:pair:${pairId}`);
228→      }
229→    } else if (tags.includes("client")) {
230→      const clientId = tags.find((t) => t !== "client");
231→      if (clientId) {
232→        await this.handleClientDisconnect(clientId);
233→      }
234→    }
235→  }
236→
237→  // ---- Alarm (auth timeout + heartbeat) ----
238→
239→  async alarm(): Promise<void> {
240→    const now = Date.now();
241→
242→    // 1. Reject clients whose auth deadline has expired
243→    const pendingClients = await this.getPendingClients();
244→    const expiredClientIds: string[] = [];
245→    for (const [clientId, deadline] of pendingClients) {
246→      if (now >= deadline) {
247→        expiredClientIds.push(clientId);
248→      }
249→    }
250→    if (expiredClientIds.length > 0) {
251→      const keysToDelete = expiredClientIds.flatMap((id) => [
252→        `pending:${id}`,
253→        `auth_token:${id}`,
254→      ]);
255→      await this.ctx.storage.delete(keysToDelete);
256→      for (const clientId of expiredClientIds) {
257→        this.rejectClient(clientId, "Authentication timeout");
258→      }
259→    }
260→
261→    // 1b. Reject pairers whose deadline has expired
262→    const pendingPairs = await this.ctx.storage.list<number>({ prefix: "pending:pair:" });
263→    for (const [key, deadline] of pendingPairs) {
264→      if (now >= deadline) {
265→        const pairId = key.slice("pending:pair:".length);
266→        const pairerWs = this.findPairerWs(pairId);
267→        if (pairerWs) {
268→          this.safeSend(pairerWs, { type: "pair_failed", message: "Pairing timed out" });
269→          try {
270→            pairerWs.close(1000, "Pairing timed out");
271→          } catch (err) {
272→            console.error("relay: failed to close expired pairer", err);
273→          }
274→        }
275→        await this.ctx.storage.delete(key);
276→      }
277→    }
278→
279→    // 2. Send heartbeat ping to server
280→    const tunnel = this.getTunnel();
281→    if (tunnel) {
282→      this.safeSend(tunnel, { type: "ping" });
283→    }
284→
285→    // 3. Reschedule for next event
286→    await this.scheduleNextAlarm();
287→  }
288→
289→  // ---- Server Message Handling ----
290→
291→  private async handleServerMessage(ws: WebSocket, frame: ServerFrame): Promise<void> {
292→    const isRegistered = await this.ctx.storage.get<boolean>("tunnelRegistered");
293→
294→    switch (frame.type) {
295→      case "register": {
296→        await this.handleRegister(ws, frame);
297→        break;
298→      }
299→      case "auth_response": {
300→        // Only registered tunnels may send auth_response
301→        if (!isRegistered) break;
302→        await this.handleAuthResponse(frame.clientId, frame.allowed, frame.reason);
303→        break;
304→      }
305→      case "pair_response": {
306→        if (!isRegistered) break;
307→        await this.ctx.storage.delete(`pending:pair:${frame.pairId}`);
308→        const pairerWs = this.findPairerWs(frame.pairId);
309→        if (!pairerWs) break;
310→        if (frame.success && "deviceToken" in frame) {
311→          this.safeSend(pairerWs, { type: "pair_success", token: frame.deviceToken });
312→        } else {
313→          const reason = "reason" in frame ? frame.reason : "Pairing failed";
314→          this.safeSend(pairerWs, { type: "pair_failed", message: reason });
315→        }
316→        // Close the one-shot pairer WS — buffered messages are sent before the close frame
317→        try {
318→          pairerWs.close(1000, "Pairing complete");
319→        } catch (err) {
320→          console.error("relay: failed to close pairer after response", err);
321→        }
322→        break;
323→      }
324→      case "data": {
325→        // Only registered tunnels may send data
326→        if (!isRegistered) break;
327→        await this.forwardToClient(frame.clientId, frame.payload);
328→        break;
329→      }
330→      case "pong": {
331→        break;
332→      }
333→    }
334→  }
335→
336→  private async handleRegister(
337→    ws: WebSocket,
338→    frame: Extract<ServerFrame, { type: "register" }>
339→  ): Promise<void> {
340→    const storedToken = await this.ctx.storage.get<string>("relayToken");
341→    if (storedToken && storedToken !== frame.relayToken) {
342→      this.safeSend(ws, { type: "error", message: "Invalid relay token" });
343→      try {
344→        ws.close(4003, "Invalid relay token");
345→      } catch (err) {
346→        console.error("relay: failed to close tunnel with bad token", err);
347→      }
348→      return;
349→    }
350→
351→    if (!storedToken) {
352→      await this.ctx.storage.put("relayToken", frame.relayToken);
353→    }
354→
355→    // Always update server name (user might have changed it)
356→    if (frame.serverName) {
357→      await this.ctx.storage.put("serverName", frame.serverName);
358→    }
359→
360→    // Mark tunnel as registered — gates auth_response/data processing
361→    await this.ctx.storage.put("tunnelRegistered", true);
362→
363→    // Clear reconnection state and notify clients server is back
364→    const wasReconnecting = await this.ctx.storage.get<number>("serverDisconnectedAt");
365→    await this.ctx.storage.delete("serverDisconnectedAt");
366→
367→    // Confirm registration to the WebSocket that sent it
368→    this.safeSend(ws, { type: "registered" });
369→
370→    // Notify already-authenticated clients that the server is back.
371→    // Pending clients are notified via the normal auth flow (they'll get "authenticated").
372→    if (wasReconnecting !== undefined) {
373→      const clients = this.ctx.getWebSockets("client");
374→      for (const clientWs of clients) {
375→        const clientId = this.ctx.getTags(clientWs).find((t) => t !== "client");
376→        if (!clientId) continue;
377→        const isPending = await this.ctx.storage.get<number>(`pending:${clientId}`);
378→        if (isPending !== undefined) continue;
379→        this.safeSend(clientWs, { type: "server_connected" });
380→      }
381→    }
382→
383→    // Always re-forward pending clients' stored auth tokens to the new tunnel.
384→    // This handles both reconnection (wasReconnecting) and tunnel replacement
385→    // (where serverDisconnectedAt was never set because the old tunnel's close
386→    // handler saw the new tunnel already existed).
387→    const pendingClients = await this.getPendingClients();
388→    for (const [pendingClientId] of pendingClients) {
389→      const storedAuthToken = await this.ctx.storage.get<string>(
390→        `auth_token:${pendingClientId}`
391→      );
392→      if (storedAuthToken) {
393→        this.safeSend(ws, {
394→          type: "client_connected",
395→          clientId: pendingClientId,
396→          deviceToken: storedAuthToken,
397→        });
398→      }
399→    }
400→
401→    // Start heartbeat
402→    await this.scheduleNextAlarm();
403→  }
