365→    await this.ctx.storage.delete("serverDisconnectedAt");
366→
367→    // Confirm registration to the WebSocket that sent it
368→    this.safeSend(ws, { type: "registered" });
369→
370→    // Notify already-authenticated clients that the server is back.
371→    // Pending clients are notified via the normal auth flow (they'll get "authenticated").
372→    if (wasReconnecting !== undefined) {
373→      const clients = this.ctx.getWebSockets("client");
374→      for (const clientWs of clients) {
375→        const clientId = this.ctx.getTags(clientWs).find((t) => t !== "client");
376→        if (!clientId) continue;
377→        const isPending = await this.ctx.storage.get<number>(`pending:${clientId}`);
378→        if (isPending !== undefined) continue;
379→        this.safeSend(clientWs, { type: "server_connected" });
380→      }
381→    }
382→
383→    // Always re-forward pending clients' stored auth tokens to the new tunnel.
384→    // This handles both reconnection (wasReconnecting) and tunnel replacement
385→    // (where serverDisconnectedAt was never set because the old tunnel's close
386→    // handler saw the new tunnel already existed).
387→    const pendingClients = await this.getPendingClients();
388→    for (const [pendingClientId] of pendingClients) {
389→      const storedAuthToken = await this.ctx.storage.get<string>(
390→        `auth_token:${pendingClientId}`
391→      );
392→      if (storedAuthToken) {
393→        this.safeSend(ws, {
394→          type: "client_connected",
395→          clientId: pendingClientId,
396→          deviceToken: storedAuthToken,
397→        });
398→      }
399→    }
400→
401→    // Start heartbeat
402→    await this.scheduleNextAlarm();
403→  }
404→
405→  // ---- Auth Delegation ----
406→
407→  private async handleAuthResponse(
408→    clientId: string,
409→    allowed: boolean,
410→    reason?: string
411→  ): Promise<void> {
412→    await this.ctx.storage.delete(`pending:${clientId}`);
413→    await this.ctx.storage.delete(`auth_token:${clientId}`);
414→
415→    if (allowed) {
416→      this.activateClient(clientId);
417→    } else {
418→      this.rejectClient(clientId, reason || "Authentication denied");
419→    }
420→  }
421→
422→  private activateClient(clientId: string): void {
423→    const ws = this.findClientWs(clientId);
424→    if (ws) {
425→      this.safeSend(ws, { type: "authenticated" });
426→    }
427→  }
428→
429→  private rejectClient(clientId: string, message: string): void {
430→    const ws = this.findClientWs(clientId);
431→    if (ws) {
432→      this.safeSend(ws, { type: "auth_failed", message });
433→      try {
434→        ws.close(4003, message);
435→      } catch (err) {
436→        console.error(`relay: failed to close rejected client ${clientId}`, err);
437→      }
438→    }
439→  }
440→
441→  // ---- Client Message Handling ----
442→
443→  private async handleClientMessage(clientId: string, json: unknown): Promise<void> {
444→    const isPending = await this.ctx.storage.get<number>(`pending:${clientId}`);
445→
446→    if (isPending !== undefined) {
447→      // Client is still pending — only accept authenticate messages
448→      const authResult = clientAuthFrameSchema.safeParse(json);
449→      if (!authResult.success) return;
450→
451→      const { token } = authResult.data;
452→      // Store the token so we can re-forward it if the server reconnects
453→      await this.ctx.storage.put(`auth_token:${clientId}`, token);
454→
455→      const tunnel = this.getTunnel();
456→      const isRegistered = await this.ctx.storage.get<boolean>("tunnelRegistered");
457→      if (tunnel && isRegistered) {
458→        this.safeSend(tunnel, {
459→          type: "client_connected",
460→          clientId,
461→          deviceToken: token,
462→        });
463→      } else if (tunnel) {
464→        // Tunnel exists but not yet registered — replacement in progress.
465→        // Leave client pending; handleRegister will re-forward the stored
466→        // auth token once the new tunnel completes registration.
467→        // The auth timeout alarm will reject naturally if registration never comes.
468→      } else {
469→        // Server tunnel is down — keep client waiting for server to return.
470→        // Suspend the short auth deadline; handleRegister will re-forward the
471→        // stored auth token when the server reconnects.
472→        const serverDisconnectedAt = await this.ctx.storage.get<number>("serverDisconnectedAt");
473→        await this.ctx.storage.put(`pending:${clientId}`, Date.now() + OFFLINE_WAIT_MS);
474→        const clientWs = this.findClientWs(clientId);
475→        if (clientWs) {
476→          const serverName = await this.ctx.storage.get<string>("serverName");
477→          this.safeSend(clientWs, {
478→            type: "server_reconnecting",
479→            serverDisconnectedAt: serverDisconnectedAt ?? Date.now(),
480→            serverName: serverName || null,
481→          });
482→        }
483→      }
484→      return;
485→    }
486→
487→    // Authenticated client — forward data to server
488→    const tunnel = this.getTunnel();
489→    if (tunnel) {
490→      this.safeSend(tunnel, {
491→        type: "data",
492→        clientId,
493→        payload: JSON.stringify(json),
494→      });
495→    }
496→  }
497→
498→  // ---- Pairer Message Handling ----
499→
500→  private async handlePairerMessage(pairId: string, frame: PairerFrame): Promise<void> {
501→    const isPending = await this.ctx.storage.get<number>(`pending:pair:${pairId}`);
502→    if (isPending === undefined) return;
503→
504→    const tunnel = this.getTunnel();
505→    const isRegistered = await this.ctx.storage.get<boolean>("tunnelRegistered");
506→    if (tunnel && isRegistered) {
507→      this.safeSend(tunnel, {
508→        type: "pair_request",
509→        pairId,
510→        code: frame.code,
511→        deviceName: frame.deviceName,
512→      });
513→    } else {
514→      const pairerWs = this.findPairerWs(pairId);
515→      if (pairerWs) {
516→        this.safeSend(pairerWs, { type: "pair_failed", message: "Server is offline" });
517→        try {
518→          pairerWs.close(1000, "Server offline");
519→        } catch (err) {
520→          console.error("relay: failed to close pairer (server offline)", err);
521→        }
522→      }
523→      await this.ctx.storage.delete(`pending:pair:${pairId}`);
524→    }
525→  }
526→
527→  // ---- Client/Server Lifecycle ----
528→
529→  private async handleClientDisconnect(clientId: string): Promise<void> {
530→    await this.ctx.storage.delete(`pending:${clientId}`);
531→    await this.ctx.storage.delete(`auth_token:${clientId}`);
532→
533→    const tunnel = this.getTunnel();
534→    if (tunnel) {
535→      this.safeSend(tunnel, {
536→        type: "client_disconnected",
537→        clientId,
538→      });
539→    }
540→  }
541→
542→  private async handleServerDisconnect(): Promise<void> {
543→    // If another tunnel is already active (e.g. old tunnel's close callback firing
544→    // after handleTunnel replaced it), skip the disconnect flow.
545→    const tunnels = this.ctx.getWebSockets("tunnel");
546→    if (tunnels.length > 0) return;
547→
548→    const existing = await this.ctx.storage.get<number>("serverDisconnectedAt");
549→    if (existing !== undefined) return; // Already handling disconnect
550→
551→    await this.ctx.storage.put("tunnelRegistered", false);
552→    const disconnectedAt = Date.now();
553→    await this.ctx.storage.put("serverDisconnectedAt", disconnectedAt);
554→
555→    const serverName = await this.ctx.storage.get<string>("serverName");
556→    const clients = this.ctx.getWebSockets("client");
557→    for (const clientWs of clients) {
558→      this.safeSend(clientWs, {
559→        type: "server_reconnecting",
560→        serverDisconnectedAt: disconnectedAt,
561→        serverName: serverName || null,
562→      });
563→    }
564→
565→    await this.scheduleNextAlarm();
566→  }
567→
568→  // ---- Data Forwarding ----
569→
570→  private async forwardToClient(clientId: string, payload: string): Promise<void> {
571→    const isPending = await this.ctx.storage.get<number>(`pending:${clientId}`);
572→    if (isPending !== undefined) {
573→      return;
574→    }
575→
576→    const ws = this.findClientWs(clientId);
577→    if (ws) {
578→      try {
579→        ws.send(payload);
580→      } catch (err) {
581→        console.error(`relay: failed to forward data to client ${clientId}`, err);
582→      }
583→    }
584→  }
585→
586→  // ---- Alarm Scheduling ----
587→
588→  private async scheduleNextAlarm(): Promise<void> {
589→    const now = Date.now();
590→    const candidates: number[] = [];
591→
592→    // Earliest pending auth deadline
593→    const pendingClients = await this.ctx.storage.list<number>({ prefix: "pending:" });
594→    for (const [, deadline] of pendingClients) {
595→      candidates.push(deadline);
596→    }
597→
598→    // Earliest pending pair deadline
599→    const pendingPairs = await this.ctx.storage.list<number>({ prefix: "pending:pair:" });
600→    for (const [, deadline] of pendingPairs) {
601→      candidates.push(deadline);
602→    }
603→
604→    // Heartbeat interval (only if server is connected)
605→    const tunnels = this.ctx.getWebSockets("tunnel");
606→    if (tunnels.length > 0) {
607→      candidates.push(now + HEARTBEAT_INTERVAL_MS);
608→    }
609→
610→    if (candidates.length > 0) {
611→      const nextAlarm = Math.min(...candidates);
612→      // Ensure alarm is at least 100ms in the future
613→      await this.ctx.storage.setAlarm(Math.max(nextAlarm, now + 100));
614→    }
615→  }
616→
617→  // ---- Helpers ----
618→
619→  /** Get pending client auth entries, filtering out pair entries that share the prefix. */
620→  private async getPendingClients(): Promise<Map<string, number>> {
621→    const entries = await this.ctx.storage.list<number>({ prefix: "pending:" });
622→    const result = new Map<string, number>();
623→    for (const [key, deadline] of entries) {
624→      if (key.startsWith("pending:pair:")) continue;
625→      result.set(key.slice("pending:".length), deadline);
626→    }
627→    return result;
628→  }
629→
630→  private findClientWs(clientId: string): WebSocket | null {
631→    const allClients = this.ctx.getWebSockets("client");
632→    for (const ws of allClients) {
633→      const tags = this.ctx.getTags(ws);
634→      if (tags.includes(clientId)) return ws;
635→    }
636→    return null;
637→  }
638→
639→  private findPairerWs(pairId: string): WebSocket | null {
640→    const allPairers = this.ctx.getWebSockets("pairer");
641→    for (const ws of allPairers) {
642→      const tags = this.ctx.getTags(ws);
643→      if (tags.includes(pairId)) return ws;
644→    }
645→    return null;
646→  }
647→
648→  private getTunnel(): WebSocket | null {
649→    const tunnels = this.ctx.getWebSockets("tunnel");
650→    return tunnels[0] ?? null;
651→  }
652→
653→  private safeSend(ws: WebSocket, data: RelayFrame | RelayClientFrame | RelayPairerFrame): void {
654→    try {
655→      ws.send(JSON.stringify(data));
656→    } catch (err) {
657→      console.error("relay: safeSend failed", err);
658→    }
659→  }
660→}
